window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]=window.__LIBQ["the-gioi-hoan-my"]["q02"]||{};window.__LIBQ["the-gioi-hoan-my"]["q02"]["characters"]={"updatedAt":"2026-07-04","count":44,"chars":[{"id":"thach-hao","name":"Thạch Hạo","aliases":["Nhóc tỳ","Hạo Thiên","Tiểu sư đệ","Nhóc siêu quậy","Tên nhóc siêu quậy ở Hư Thần giới","Nhân thần cộng phẫn","Tiểu tử","Tiểu ca ca","Bóng Lông","Tiểu mập mạp","Ca ca của Thanh Phong","thằng nhóc quỷ","Nhóc Tỳ","Thằng bé hung tàn","Tiểu ma vương","Tiểu sư đệ Bổ Thiên các","Thiếu niên Nhân tộc","thiếu niên Nhân tộc","Thích Uống Sữa Thú Nhất","Tham ăn","thiếu niên hung tàn"],"gioiTinh":"nam","canhGioiCaoNhat":"Đệ lục Động Thiên (@c0101)","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"major","chuong":"@c0101","tieuDe":"Trộm Hắc Sát Liên, đột phá đệ lục Động Thiên","text":"Tại chiến trường thứ hai của Bổ Thiên các, Nhóc tỳ trinh sát hang Hắc hổ Thú Vương rồi rút lui vì quá nguy hiểm; dùng cự thạch phủ phù văn chọc giận sáu bảy con bá chủ tạo thú triều để dụ Thú Vương rời hang, nhân đó phóng vào địa quật đào trộm Hắc Sát Liên rồi bỏ chạy; ăn sạch linh dược, bôi chất lỏng còn sót lên hai con Thanh Lang xóa dấu vết, sau đó chìm đáy sông tu hành suốt đêm luyện hóa dược tính, mở khẩu thứ sáu Động Thiên khi mới 9 tuổi rưỡi.","anchor":"Đến lúc này, nó mở ra khẩu thứ sáu Động Thiên, thực lực lại lần nữa tăng lên một đoạn"},{"importance":"major","chuong":"@c0101","tieuDe":"Một búa quật ngã Tiêu Thiên","text":"Trở lại chiến trường tan hoang sau thú triều để đoạt thêm Bổ Thiên thạch, Nhóc tỳ ẩn thân quan sát; chính là đứa nhỏ mà Tiêu Thiên từng đánh lén một chưởng và kiêng kỵ. Khi Tiêu Thiên đứng thứ nhất trong hơn chín vạn người vẫn bất an, Nhóc tỳ từ cây gỗ khô sau lưng nứt ra, dùng Bạch cốt đại bổng như búa đập thẳng vào sau gáy, hai búa liên tiếp quật ngã kẻ mạnh nhất chưa kịp nhìn rõ đối phương.","anchor":"Tiêu Thiên tròng mắt trợn tròn, bị một búa quật ngã"},{"importance":"normal","chuong":"@c0102","tieuDe":"Đánh lén cướp bảo vật Tiêu Thiên","text":"Nhóc tỳ dùng Bạch cốt đại bổng đánh lén Tiêu Thiên ngất, báo thù việc từng bị đánh lén lúc bị Cổ Ngạc đuổi giết; lục soát lấy 25 khối Bổ Thiên thạch cùng 2 bình bảo đan (bổ tinh huyết + trị trọng thương); về sau vì Bổ Thiên thạch đã mất hiệu lực sau bạo động khu thứ tám nên đánh lén Tiêu Thiên lần 2 rồi ném trả bao Bổ Thiên thạch, dặn cả vốn lẫn lời phải hoàn lại; cuối cùng nhặt lại một Đế tử bị bỏ sót rồi cô đơn đi về khu thứ tám.","anchor":"Ngươi cũng dám đánh lén ta nữa àh... Thôi coi như huề nhau vậy."},{"importance":"major","chuong":"@c0105","tieuDe":"Ăn sống Hắc Sát Liên đột phá Động Thiên","text":"Trộm rồi nhai ngấu nghiến cả gốc Hắc Sát Liên như củ cà rốt để đột phá đệ lục Động Thiên, chỉ hấp thu khoảng ba thành dược liệu khiến bảo dược không thể sống lại; sau đó giấu tổng cộng mười tám bộ bảo cốt ở chiến trường thứ hai, Bổ Thiên các chỉ tìm được sáu bộ; hắn đổi hình dạng trà trộn giữa ba ngàn đệ tử để lẩn tránh truy lùng.","anchor":"chỉ là để đột phá đệ lục Động Thiên mà thôi"},{"importance":"normal","chuong":"@c0106","tieuDe":"Trà trộn nhập môn Bổ Thiên các","text":"Đã thay đổi hình dạng thành mập ục ịch, giả khóc bám vào một cụ già xa lạ để trà trộn vào ba ngàn thiếu niên nhập môn; vừa được an ủi liền ngừng khóc, mặt không một giọt nước mắt, xoay người rời đi; sau đó bái tượng Tổ sư, quấy nhiễu hỏi han về con gái Nhân Hoàng và Trùng Đồng giả; bị Hùng Phi và Trác Vân — hai trưởng lão từng bị nó chọc đến hộc máu — chọn làm đệ tử; phát hiện Thanh Phong bị thương, âm thầm nắm chặt nắm đấm quyết hỏi cho ra lẽ.","anchor":"trên mặt ngay cả một giọt nước mắt cũng không có, xoay người rời đi"},{"importance":"major","chuong":"@c0106","tieuDe":"Vừa nhập môn đã thành tội phạm truy nã","text":"Tảng đá Tế Linh mang chữ khiêu khích 「Nắm Búa Nơi Tay, Ta Có Thiên Hạ」 do chính nó để lại được đưa lên trước ba ngàn tân đệ tử; Hùng Phi trưởng lão phát lệnh truy nã Nhóc siêu quậy ngay trong nội bộ môn phái, treo thưởng đệ tử trọng yếu nhất; Thạch Hạo trốn vào sâu trong đám người, cùng hô lớn 'bắt lấy tên nhóc này' để che giấu thân phận.","anchor":"Nắm Búa Nơi Tay, Ta Có Thiên Hạ"},{"importance":"normal","chuong":"@c0107","tieuDe":"Sóng gió khắp Hư Thần giới","text":"Hành động đào Bảo Cốt khu thứ tám, trộm Bảo Dược và lưu tảng đá ở chiến trường thứ hai làm cả Hư Thần giới bàn tán; Hùng Phi và Trác Vân trưởng lão tức phun máu, phải truy nã; nhóc tỳ nhập khu đệ tử mới phải xách nước, khai thác quặng, bất mãn vì học chậm; sai Bóng Lông điều tra, biết Thanh Phong bị bắt nạt liền vạch kế trừng trị nhắm vào chỗ dựa họ Vũ, tính kéo Thạch Nghị vào cuộc.","anchor":"nó không chỉ đào Bảo Cốt của khu thứ tám, còn ăn trộm thêm một cây Bảo Dược"},{"chuong":"@c0108","importance":"normal","tieuDe":"Gài bẫy Chu Vũ Hào bị đám đông truy sát","text":"Trốn trong đám đệ tử quan sát, thấy Thanh Phong bị ám toán thì ánh mắt lạnh; khao khát cho Bóng Lông vào Tàng Kinh các; sau đấm Chu Vũ Hào nở hoa mặt rồi hô hoán vu hắn là đồng bọn nhóc siêu quậy, kích động mấy trăm đệ tử mới đuổi đánh hắn đến răng bay hộc máu.","anchor":"bị một thằng nhóc con một quyền oanh ở trên mặt"},{"importance":"normal","chuong":"@c0109","tieuDe":"Giật dây gây xung đột đẫm máu","text":"Trà trộn trong đám đệ tử mới, Thạch Hạo là kẻ kêu gào đầu, ra quyền đầu, dùng Phù Chưởng trọng thương ba người (Chu Vũ Hào và hai người cứu) rồi lui về sau đắc ý, khiến xung đột lan thành nội chiến hơn ba ngàn người; sau đó nháy mắt tươi vui với Thanh Phong và tò mò hỏi sư tỷ về hồ lô vỏ vàng, rồi nhìn thấy Thạch Nghị đi trên con đường vào Thượng Cổ Thánh Viện.","anchor":"người kêu gào đầu tiên tự nhiên là nó, người đánh một quyền cũng là nó, thời khắc mấu chốt ra tay trọng thương ba người kia cũng vẫn là nó"},{"importance":"normal","chuong":"@c0111","tieuDe":"Đối mặt u linh Thượng Cổ đòi kiếm","text":"Tại nơi ở Tế Linh, một ông lão tử khí cắm cổ kiếm trên đầu liên tục cản đường Thạch Hạo; cầu cứu Tế Linh bất thành, hồ lô vỏ xanh phát khí Hỗn Độn đẩy lui nó; nó hứa sau này tìm giúp trả kiếm khiến ông lão biến mất giữa sấm chớp; ông lão xuất hiện lần hai náo loạn đệ tử, cuối cùng nó hết sợ, cưỡi lên cổ ông lão tóc xám.","anchor":"Được, sau này tìm giúp ngươi, trả kiếm lại cho ngươi"},{"importance":"normal","chuong":"@c0112","tieuDe":"Đập nhổ cổ kiếm trên đầu Tử Thần","text":"Cưỡi trên cổ vị thần quái Thượng Cổ bị kiếm đâm xuyên đầu, dùng đỉnh đồng gõ leng keng đốm lửa tứ tung định nhổ thanh cổ kiếm mà tưởng là Bảo Cụ chí cường; nghe được Hắn là Tử Thần ai bị chọn đều chết nên hoảng, nhảy bám Trác Vân rồi Hùng Phi suýt bóp ngất; biết phải tìm kiếm thật của Tử Thần ở Bách Đoạn sơn mạch nếu không sẽ chết, ban đầu đòi không đi nhưng nghe nói nay có cơ duyên lớn thì kinh ngạc.","anchor":"Lão bá, thanh kiếm trên đầu bác nhất định là Bảo Cụ chí cường"},{"importance":"major","chuong":"@c0113","tieuDe":"Thân phận bại lộ trước Hùng Phi","text":"Nhóc tỳ được các nguyên lão Bổ Thiên các du thuyết vào Bách Đoạn sơn tìm cơ duyên; nó mặc cả đòi chỗ tốt, tuyên bố muốn bắt Kim Sí Đại Bằng non khiến cả đoàn cứng đơ; khi bốn lão già mắt ánh xanh thử thân thể, nó phản kích đấm trúng một lão gây tiếng sấm rền chấn động cung điện, được khen thân thể nghịch thiên; ngay lúc đó Hùng Phi nhận ra nó chính là thằng nhóc quỷ từng gây loạn khiến hắn và Trác Vân khốn đốn — thân phận bại lộ.","anchor":"Ngươi... Ngươi chính là thằng nhóc quỷ kia?!"},{"importance":"normal","chuong":"@c0113","tieuDe":"Nhận nhiệm vụ tìm Bất Lão thần tuyền","text":"Bốn lão tiền bối giao nhóc tỳ vào Bách Đoạn sơn tìm Bất Lão thần tuyền mang về, hứa khắc tên lên Bất Hủ Thần Bi và cho vào Tàng Kinh các chọn Bảo Thuật; nó mặc cả đòi ở Tàng Kinh các một tháng và hơn một loại bảo thuật; sau đó nó trộm ăn Tuyết Ngọc Sâm rồi khai Đào Dã cho, và mang một cây linh dược nguyên vẹn tặng đệ đệ Thanh Phong ở Thiên tài doanh khiến Thanh Phong sợ tưởng đồ trộm; nó công khai mở kèo đánh cược cây linh dược, khiêu khích cả đám thiếu niên lẫn thiếu nữ.","anchor":"Sau khi ngươi tiến vào Bách Đoạn sơn, nhất định phải lưu ý, tìm kiếm Bất Lão thần tuyền"},{"importance":"major","chuong":"@c0114","tieuDe":"Đại náo Thiên tài doanh, thắng 28 trận","text":"Bị đám thiên tài vây ép, nhóc tỳ bày trò “đổ chiến” buộc ai muốn đánh phải đặt chiến lợi phẩm xuống đất; dùng Phù Văn hóa búa bạc đánh tan Khổng Tước xanh rồi khống chế Ngạn Tâm, tạo cối xay bạc nghiền tan chiến mâu đánh bại Phiêu Tuyết, đấm gục Chu Vũ Hào; thắng liên tiếp 28 trận chấn động toàn khu và công khai tuyên bố bảo vệ Thanh Phong — ai bắt nạt Thanh Phong là bắt nạt nó.","anchor":"thắng suốt hai mươi tám trận"},{"importance":"major","chuong":"@c0114","tieuDe":"Rời Bổ Thiên các đi Bách Đoạn sơn","text":"Sau nhiều ngày kết giao bạn bè ở Thiên tài doanh, nhóc tỳ dặn dò Thanh Phong yên tâm tu hành (đã nhờ người trong môn và Trưởng Lão hội chiếu cố), rồi cùng đoàn đệ tử theo thông đạo hồ lô xanh rời khỏi Bổ Thiên các, lên đường hướng dãy Bách Đoạn sơn — nơi anh kiệt hội tụ.","anchor":"hướng tới dãy Bách Đoạn sơn"},{"importance":"normal","chuong":"@c0115","tieuDe":"Bị nhiều thế lực truy sát, ra lệnh bắt sống","text":"Tại Đoạn Không thành, nhóc tỳ nghe ngóng rồi phải lét lút trốn vì nhiều thế lực lớn muốn lấy đầu; có phe ra yêu cầu bắt sống (được phép làm mất tay chân nhưng phải giữ mạng); nó tự suy đoán kẻ săn mình hơn phân nửa là gia tộc đã mất Xích Vũ Bảo Phiến, số còn lại thì bỏ mặc hẹn gặp trên chiến trường, quyết tâm tiến vào Bách Đoạn sơn.","anchor":"Muốn bắt sống ta, hơn phân nửa là gia tộc mất đi Xích Vũ Bảo Phiến"},{"importance":"normal","chuong":"@c0116","tieuDe":"Cải trang nhóc tỳ tại Đoạn Không thành","text":"Cải trang thành nhóc tỳ đi trong đội năm thiên tài Bổ Thiên các tại Đoạn Không thành chờ vào Bách Đoạn sơn; chạm trán Thái Cổ di chủng Phì Di, né đòn quật đuôi rồi lớn tiếng cảnh cáo ngược khiến cả phố sững sờ, còn Phì Di cảm ứng khí tức hung mãnh giống mình; tiền thưởng bắt đầu nó tăng gấp đôi, có người nghi nó ẩn trong đội Bổ Thiên các; nó còn giỡn cợt đánh mông sư tỷ nên bị năm thiên tài đuổi đánh; cuối chương Vũ tộc xác định tên thật nó là Hạo Thiên và ra lệnh diệt trừ.","anchor":"nó cảm ứng được một khí tức rất hung mãnh khá giống mình"},{"importance":"normal","chuong":"@c0117","tieuDe":"Náo loạn nhập Bách Đoạn Sơn","text":"Vác bao tải to như chuyển nhà, khoe là “bảo bối” khiến cả đám dị tộc chú ý rồi hóa đá khi lộ ra chỉ là nồi niêu xoong chảo, gia vị “trưng dụng” cả nhà bếp một môn phái; theo nhóm Bổ Thiên các qua thông đạo ra tiểu thế giới linh khí đậm đặc; vào rừng núi liền tung hoành như rồng về biển rộng khiến thiên tài các chủng tộc kinh sợ lùi bước, đụng gãy cao thủ Thụ tộc định đánh lén và đuổi bắt chim lửa Đại Hồng cùng Nhân Hùng Tiểu Hắc để làm đồ ăn.","anchor":"Đại Hồng, đừng có chạy, mau vào bát nào!"},{"importance":"normal","chuong":"@c0118","tieuDe":"Đả thương Hỏa Vân Tước đoạt thịt","text":"Trong tiểu thế giới, nhóc tỳ săn đuổi Nhân Hùng một sừng và Hỏa Vân Tước; triệu khay bạc như Thần Nguyệt chắn biển lửa Hỏa văn, dùng Ma Cầm thời Thái Cổ, tia chớp vàng cực tốc và trăng bạc đả thương Hỏa Vân Tước, chém rớt hơn hai mươi cân thịt; cả nhóm nấu ăn nhận ra là huyết nhục bảo dược khiến tinh khí lớn mạnh.","anchor":"Một khối thịt rớt ra, con chim rơi xuống cực nhanh."},{"importance":"normal","chuong":"@c0118","tieuDe":"Đối mặt sinh vật ánh bạc","text":"Sinh vật hình người ánh bạc phục kích đoạt bốn gốc Xích Lan, giẫm sập vách đá suýt chôn vùi sư huynh; nhóc tỳ lao vào kéo cánh tay sư huynh ra khỏi cự thạch; bị sinh vật ánh bạc chiêu dụ làm chiến bộc và nhắc Hoàng Kim sư tử chín đầu, nhưng nhóc tỳ coi nó như món ăn, dọa chôn sống hay hấp cách thủy.","anchor":"Nó bắt được cánh tay của sư huynh lôi mạnh ra ngoài"},{"importance":"major","chuong":"@c0119","tieuDe":"Giết Thái Cổ di chủng màu bạc","text":"Đơn độc đấu sinh linh màu bạc (Thái Cổ di chủng, hậu duệ Vương tộc) tự xưng “Vương tương lai”; dùng chớp giật vàng cùng ba Bảo Cụ (Cốt Kính, Cốt Tiễn, quạt cướp được), triển bảo thuật Toan Nghê Vương, rút Cốt Tiễn vàng bẻ gãy chủy thủ bạc rồi chặt tay đối thủ; đuổi theo cắt cổ, đánh đầu thành tro; bi phẫn vì cây quạt bạc chiến lợi phẩm nát hơn nửa; sau đó không muốn ăn sinh linh hình người nên quyết đem di chủng đi trao đổi.","anchor":"cánh tay trái của hắn bị cắt đứt, máu me tung tóe"},{"importance":"normal","chuong":"@c0119","tieuDe":"Rao đổi di chủng, gặp con gái Nhân Hoàng","text":"Hô lớn hỏi ai muốn đổi Thái Cổ di chủng làm dãy núi rung động, có tiếng đáp đồng ý; vượt một dãy núi thì gặp hơn bốn mươi thiên tài hộ tống xe phượng đỏ thẫm, nhận ra là con gái nhỏ của Nhân Hoàng — sư muội cùng môn; đối phương đồng ý trao đổi.","anchor":"Có ai muốn đổi Thái Cổ di chủng không?"},{"importance":"major","chuong":"@c0120","tieuDe":"Đột phá mở Động Thiên thứ bảy","text":"Trao đổi con sinh linh màu bạc (Linh Tộc) lấy Tử Vân Tâm theo quyết định của Hỏa Linh Nhi; bị đám thiên tài nhận ra là nhóc siêu quậy và vây bắt nên bỏ chạy vào rừng; sau vài ngày luyện hóa Tử Vân Tâm trong hang cổ, đột phá mở ra miệng Động Thiên thứ bảy, khí tức kinh khủng khiến mãnh thú chạy trốn; sau đó đánh chết sinh linh mọc sừng người của Vũ Vương và bắn mười tia chớp giết mấy Dị tộc còn lại; đồng ý gia nhập liên minh đi Thần Quật nhưng ôm thù muốn hầm con sư tử dị dạng, còn vỗ mông công chúa để trêu ngược.","anchor":"nhóc tỳ đột phá, mở ra trên người miệng Động Thiên thứ bảy"},{"importance":"normal","chuong":"@c0121","tieuDe":"Một chọi ba Thái Cổ di chủng","text":"Băng qua thảo nguyên Thần Quật, chọc Hỏa Linh Nhi khiến nàng dệt cánh Chu Tước truy sát; tới chân núi Thần Quật chạm ba Thái Cổ di chủng cầm đầu (Hoàng Kim sư tử chín đầu, Ngân Huyết cự nhân, Vũ Vương) tranh nhau thu làm chiến sủng; nhóc tỳ đấm Ngân Huyết chảy máu tay, đá Vũ Vương văng hộc máu, dùng bảo cốt Toan Nghê thi triển Nghịch chuyển phản đòn Sư Tử chín đầu — một mình đánh lui hai, ngang sức Sư Tử chín đầu; xác nhận đã ăn thịt Mộc Phong của Linh tộc và tuyên bố mục đích vào Bách Đoạn sơn là hàng phục một con Thái cổ hung thú non.","anchor":"một người lại tấn công ba vị Thái Cổ di chủng, đánh lui hai người"},{"importance":"normal","chuong":"@c0122","tieuDe":"Đánh bại và cưỡi Sư Tử chín đầu","text":"Trên thảo nguyên Đại hoang, tuy cảnh giới thấp hơn Nhóc tỳ vẫn đại chiến ngang tài với Hoàng Kim sư tử, dùng bảo kính, Cốt Tiễn (Kim Giao tiễn), khay bạc, Bảo Thuật Toan Nghê và Thanh Lân Ưng; đây là lần đầu bị thương kể từ khi vào Tiểu Thế Giới; sau đó vận Nguyên Thủy Chân Giải cùng Chiến Thần Đồ Lục, tổ hợp Phù Văn thường hóa giải Vô Úy Sư Tử ấn rồi nhảy lên cưỡi trấn áp sư tử, do dự giữa làm thịt hay giữ làm thú cưỡi.","anchor":"Nhóc tỳ nhảy lên một cái, cưỡi trên người của Sư Tử chín đầu, nâng quyền lên mà đập mạnh, cực kỳ uy phong"},{"importance":"normal","chuong":"@c0124","tieuDe":"Ôm trứng thần trốn bầy sói bạo động","text":"Ôm trứng thần màu vàng chạy trốn giữa đại thảo nguyên bạo động ban đêm, bị vô số cự lang cùng mấy chục Lang Vương hiểu Bảo Thuật truy sát; dùng Cốt Tiễn màu vàng phá vòng vây mở đường máu, đạp cốt kính bay cao rồi nhảy xuống sông cắt mùi; suy đoán trứng là hậu duệ Thần linh nên quyết định nhóm lửa nướng/luộc ăn, cuối cùng vỏ trứng vỡ ra ấp thành một thần linh non cuộn tròn trong lòng bàn tay.","anchor":"Nhóc tỳ vận dụng Cốt Tiễn màu vàng phá vòng vây mở ra một con đường máu xông về phương xa"},{"importance":"major","chuong":"@c0125","tieuDe":"Đoạt Ấu Thần, chặt cánh tay Vũ Vương","text":"Ấu Thần (hậu đại Lang Thần) chào đời hấp thu bảo thuật để trưởng thành; Thạch Hạo phun tia chớp cháy đen bàn tay người khổng lồ Ngân Huyết, huơ Cốt Tiễn vàng kim đánh gãy hung đao và chặt đứt một cánh tay Vũ Vương khiến các thế lực rút lui; thí nghiệm điện giật sói con suýt chết, dùng Tham Cốt pháp thăm dò cốt cách sói con nhưng không thấy phù cốt/ấn ký; hỏi Hỏa Linh Nhi có sữa không nên bị đuổi đánh hai giờ, sau nhờ nàng nuôi sói con bằng Linh dược và trái tim hung thú.","anchor":"Cốt Tiễn vọt tới không những đánh gãy cốt đao mà còn chặt đứt một cánh tay của Vũ Vương rơi xuống, máu phun tung tóe."},{"importance":"major","chuong":"@c0125","tieuDe":"Thu phục Sư Tử chín đầu làm thú cưỡi","text":"Sau mấy ngày truy đánh, khi cả hai rớt xuống thác nước Thạch Hạo cưỡi được lên lưng Sư Tử chín đầu, ép nó làm thú cưỡi kiêm tiểu đệ, đòi Cửu Linh Vương đại lễ mấy trăm cân Linh dược hoặc một cây Thánh dược, rồi nhờ nó thông linh dẫn tìm Bất Lão Thần Tuyền; giao Ấu Thần cho Hỏa Linh Nhi nuôi rồi cưỡi Sư Tử rời đi.","anchor":"hãy để cho ta cảm hóa ngươi, khiến ngươi tâm phục khẩu phục cam nguyện làm thú cưỡi của ta"}],"tuViMoc":[{"chuong":"@c0101","canhGioi":"Đệ lục Động Thiên","text":"Chìm đáy sông tu hành suốt đêm, luyện hóa dược tính Hắc Sát Liên thành hỏa diễm đen rèn gân cốt, mở ra khẩu thứ sáu Động Thiên khi mới 9 tuổi rưỡi — cảnh giới kinh người, cảm thấy toàn thân đặc biệt cường đại.","importance":"major"},{"chuong":"@c0105","canhGioi":"Đệ lục Động Thiên","text":"Đột phá lên đệ lục Động Thiên nhờ ăn sống Hắc Sát Liên của Bổ Thiên các.","importance":"minor"},{"chuong":"@c0120","canhGioi":"Động Thiên thứ bảy","text":"Sau khi luyện hóa Tử Vân Tâm trong hang cổ, đột phá mở ra miệng Động Thiên thứ bảy trên người; dung nham trong miệng núi lửa cuồn cuộn chảy vào cơ thể, tốc độ đột phá liên tiếp trong thời gian ngắn được mô tả là hù chết người.","importance":"major"}],"nhanMach":[{"ten":"Tiêu Thiên","tag":"doi-thu","quanHe":"Đối thủ tại chiến trường thứ hai — bị Nhóc tỳ đánh lén một búa quật ngã","ghiChu":"Tiêu Thiên từng đánh lén Nhóc tỳ một chưởng và kiêng kỵ vì đối phương giấu mặt"},{"ten":"Tiêu Thiên","tag":"doi-thu","quanHe":"Kẻ đối đầu qua lại đánh lén","ghiChu":"Nhóc tỳ đánh lén Tiêu Thiên ngất 2 lần, cướp rồi trả lại Bổ Thiên thạch, hẹn cả vốn lẫn lời phải hoàn lại (@c0102)"},{"ten":"Trác Vân","tag":"doi-thu","quanHe":"Trưởng lão Bổ Thiên các bị hắn trộm bảo dược, phun máu vì mất Hắc Sát Liên."},{"ten":"Hùng Phi","tag":"doi-thu","quanHe":"Trưởng lão Bổ Thiên các suy ra hắn là thủ phạm và ra lệnh truy lùng."},{"ten":"Thạch Nghị","tag":"doi-thu","quanHe":"Người giữ kỷ lục ở Hư Thần Giới bị hắn phá; được dự báo thành đối thủ tương lai."},{"ten":"Hùng Phi","tag":"su-mon","quanHe":"Trưởng lão chọn làm sư phụ (từng bị Thạch Hạo chọc đến hộc máu)","ghiChu":"@c0106"},{"ten":"Trác Vân","tag":"su-mon","quanHe":"Trưởng lão chọn làm sư phụ (từng bị Thạch Hạo chọc đến hộc máu)","ghiChu":"@c0106"},{"ten":"Thiếu nữ áo trắng","tag":"su-mon","quanHe":"Sư tỷ Bổ Thiên các dẫn dắt, nhéo má trêu","ghiChu":"@c0106"},{"ten":"Thanh Phong","tag":"ban-be","quanHe":"Thân như anh em ruột; phát hiện bị thương","ghiChu":"@c0106"},{"ten":"Thanh Phong","tag":"ban-be","quanHe":"Tiểu đệ thân thiết cần bảo vệ","ghiChu":"Vạch kế trừng trị bọn thiếu niên bắt nạt Thanh Phong. @c0107"},{"ten":"Thạch Nghị","tag":"ho-hang","quanHe":"Người tính lôi kéo vào việc đối phó Vũ tộc","ghiChu":"@c0107"},{"ten":"Chu Vũ Hào","tag":"doi-thu","quanHe":"Kẻ ám toán Thanh Phong, bị nhóc tỳ gài trừng trị","ghiChu":""},{"ten":"Thạch Nghị","tag":"ho-hang","quanHe":"Người thân cùng bộ; được Thạch Hạo nhìn thấy đang bước trên con đường vào Thượng Cổ Thánh Viện","ghiChu":"@c0109"},{"ten":"Tử Thần","tag":"khac","quanHe":"U linh tử khí Thượng Cổ cản đường đòi trả kiếm; nó hứa tìm giúp trả kiếm rồi cưỡi lên cổ ông lão","ghiChu":"@c0111"},{"ten":"Bốn lão tiền bối Bổ Thiên các","tag":"su-mon","quanHe":"Bốn cường giả mắt ánh xanh thử thân thể nó rồi giao nhiệm vụ Bất Lão thần tuyền","ghiChu":"@c0113"},{"ten":"Thiếu nữ áo xanh","tag":"doi-thu","quanHe":"Thiếu nữ ~15-16 tuổi bước tới khiêu chiến để đoạt cây linh dược","ghiChu":"@c0113"},{"ten":"Thanh Phong","tag":"ho-hang","quanHe":"Đệ đệ","ghiChu":"Nhóc tỳ công khai bảo vệ, khích lệ Thanh Phong tu hành đột phá; ai bắt nạt Thanh Phong là bắt nạt nó (@c0114)."},{"ten":"Ngạn Tâm","tag":"doi-thu","quanHe":"Đối thủ đấu cược","ghiChu":"Đánh tan Khổng Tước xanh và lưới ngọc bích của nàng, khống chế bắt sống (@c0114)."},{"ten":"Phiêu Tuyết","tag":"doi-thu","quanHe":"Đối thủ đấu cược","ghiChu":"Nghiền tan chiến mâu, điểm eo phẩy chưởng thắng hoàn toàn (@c0114)."},{"ten":"Chu Vũ Hào","tag":"doi-thu","quanHe":"Cựu thù","ghiChu":"Đấm một quyền vào mặt khiến hắn hôn mê; hắn nhận ra nhóc tỳ là ca ca của Thanh Phong (@c0114)."},{"ten":"Vũ Phong","tag":"doi-thu","quanHe":"Cường giả quan sát","ghiChu":"Được giục ra áp chế nhưng lắc đầu không xuất thủ, chỉ lóe tinh quang trong mắt (@c0114)."},{"ten":"Đào Dã","tag":"an-nhan","quanHe":"Người báo tin","ghiChu":"Cho biết Thạch Nghị, con gái Nhân hoàng, hậu duệ Thái cổ di chủng đã được hộ tống đến Bách Đoạn sơn trước (@c0114)."},{"ten":"Đào Dã","tag":"su-mon","quanHe":"Nguyên lão Bổ Thiên các dẫn đội hộ tống","ghiChu":"Cùng đoàn tới Đoạn Không thành, Bách Đoạn sơn"},{"ten":"Thạch Nghị","tag":"khac","quanHe":"Được nêu làm mốc so sánh sức mạnh","ghiChu":"Vũ tộc lưu ý thân thể Hạo Thiên kinh người không kém Nghị nhi"},{"ten":"Thạch Tử Lăng","tag":"ho-hang","quanHe":"Nghi liên hệ huyết thống","ghiChu":"Vũ tộc nhận xét lông mày khóe mắt Hạo Thiên giống Thạch Tử Lăng năm đó (chỉ là nhận xét giống, chưa khẳng định)"},{"ten":"Đào Dã","tag":"su-mon","quanHe":"Trưởng bối Bổ Thiên các hộ tống, nhiều lần bị Thạch Hạo chọc tức đến đen mặt","ghiChu":"@c0117"},{"ten":"Đại Hồng","tag":"doi-thu","quanHe":"Chim lửa bị Thạch Hạo đuổi bắt để làm đồ ăn","ghiChu":"@c0117"},{"ten":"Sinh vật hình người ánh bạc","tag":"doi-thu","quanHe":"Cường giả bí ẩn tự xưng làm vương/chủ nhân, muốn thu nhóc tỳ làm chiến bộc","ghiChu":"Đoạt bốn gốc Xích Lan, phục kích nhóm Bổ Thiên các @c0118"},{"ten":"Đại Hồng","tag":"doi-thu","quanHe":"Hung cầm Hỏa Vân Tước bị nhóc tỳ đả thương đoạt thịt","ghiChu":"@c0118"},{"ten":"Sinh linh màu bạc","tag":"doi-thu","quanHe":"Kẻ địch bị Thạch Hạo giết trong trận đơn đấu","ghiChu":"Thái Cổ di chủng hậu duệ Vương tộc"},{"ten":"Sư Tử chín đầu","tag":"doi-thu","quanHe":"Thái Cổ di chủng muốn thu Thạch Hạo làm chiến phó","ghiChu":"Chỉ được nhắc tên"},{"ten":"Hỏa Linh Nhi","tag":"su-mon","quanHe":"Con gái nhỏ của Nhân Hoàng, sư muội cùng môn Bổ Thiên các, đồng ý trao đổi di chủng","ghiChu":""},{"ten":"Hỏa Linh Nhi","tag":"dong-minh","quanHe":"Cùng Bổ Thiên các nên bị nhóc tỳ gọi đùa là sư muội; nàng quyết đổi Tử Vân Tâm lấy Linh Tộc rồi ra lệnh vây bắt, sau lại chiêu mộ nhóc tỳ vào liên minh đi Thần Quật; bị nhóc tỳ vỗ mông trêu ngược.","ghiChu":"@c0120"},{"ten":"Hoàng Kim sư tử chín đầu","tag":"doi-thu","quanHe":"Thái Cổ di chủng chặn ải Thần Quật, tranh thu nhóc tỳ làm chiến phó rồi giao chiến","ghiChu":"Mở tranh nhận diện, đại chiến ngang sức @c0121"},{"ten":"Ngân Huyết cự nhân","tag":"doi-thu","quanHe":"Bị nhóc tỳ đấm chảy máu bàn tay","ghiChu":"@c0121"},{"ten":"Vũ Vương","tag":"doi-thu","quanHe":"Bị nhóc tỳ đá văng hộc máu","ghiChu":"@c0121"},{"ten":"Mộc Phong","tag":"doi-thu","quanHe":"Kẻ Linh tộc đi tìm nhóc tỳ, bị nhóc tỳ ăn thịt","ghiChu":"@c0121"},{"ten":"Sư Tử chín đầu","tag":"doi-thu","quanHe":"Đối thủ đại chiến trên thảo nguyên, bị đánh bại rồi bị cưỡi trấn áp làm thú cưỡi","ghiChu":"Gặp @c0122"},{"ten":"Hỏa Linh Nhi","tag":"doi-thu","quanHe":"Truy đuổi cướp trứng thần","ghiChu":"Xông vào đại chiến khi bắt gặp nhóc tỳ nướng trứng (@c0124)"},{"ten":"Ấu Thần","tag":"dong-minh","quanHe":"Linh thú Thạch Hạo đoạt được và nuôi","ghiChu":"Hậu đại Lang Thần, sói con bám dính Thạch Hạo"},{"ten":"Sư Tử chín đầu","tag":"dong-minh","quanHe":"Thú cưỡi kiêm tiểu đệ bị thu phục","ghiChu":"Cháu Cửu Linh Vương, phát thệ dẫn tìm Bất Lão Thần Tuyền"},{"ten":"Cửu Linh Vương","tag":"doi-thu","quanHe":"Bị Thạch Hạo đòi đại lễ qua Sư Tử chín đầu","ghiChu":"Tổ phụ/họ hàng của Sư Tử chín đầu"}],"tuiDo":{"phapBao":[{"ten":"Bạch cốt đại bổng","loai":"vũ khí","trangThai":"dang-co","moTa":"Cây gậy lớn bằng xương trắng, dùng như búa tập kích; hai búa đập vào gáy quật ngã Tiêu Thiên.","nguon":"@c0101"}],"danDuoc":[{"ten":"Hắc Sát Liên","trangThai":"da-dung","moTa":"Đào trộm từ địa quật Hắc hổ, ăn sạch luyện hóa để đột phá đệ lục Động Thiên.","nguon":"@c0101"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0101","@c0102","@c0105","@c0106","@c0107","@c0108","@c0109","@c0111","@c0112","@c0113","@c0114","@c0115","@c0116","@c0117","@c0118","@c0119","@c0120","@c0121","@c0122","@c0124","@c0125"]},{"id":"tieu-thien","name":"Tiêu Thiên","aliases":["Thiếu niên áo bào màu bạc","Thiếu niên áo bạc","Thiên hạ đệ nhất thiên tài"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên áo bào màu bạc tu vi kinh người tại chiến trường thứ hai, được xem là số một trong hơn chín vạn người; bị Nhóc tỳ một búa quật ngã.","vaiTro":"Đối thủ mạnh nhất của Nhóc tỳ tại chiến trường thứ hai.","tinhCach":[{"text":"Cường đại nhưng cẩn trọng, cảnh giác — bất an ám ảnh vì đối tượng giấu mặt từng đánh lén.","chuong":"@c0101"}],"tabs":{"diem":[{"text":"Một đêm chinh chiến thu được 16 khối Bổ Thiên thạch, đám bại trận cho là đứng thứ nhất trong hơn chín vạn người.","chuong":"@c0101"}],"kinhLich":[{"importance":"normal","chuong":"@c0101","tieuDe":"Áp đảo chiến trường rồi bị quật ngã","text":"Áo bào màu bạc, tu vi kinh người, một đêm chinh chiến thu 16 khối Bổ Thiên thạch, thắng cả thiếu niên Mộc tộc, nuốt bảo đan khôi phục cường thịnh và được tán tụng là số một; nhưng vẫn bất an vì đứa nhỏ giấu mặt hắn từng đánh lén một chưởng, cuối cùng bị Nhóc tỳ dùng Bạch cốt đại bổng đánh lén sau gáy hai búa quật ngã.","anchor":"hắn đã thu được 16 khối Bổ Thiên thạch"},{"importance":"normal","chuong":"@c0102","tieuDe":"Bị Nhóc tỳ đánh lén ngất hai lần","text":"Tiêu Thiên bị Nhóc tỳ dùng Bạch cốt đại bổng đánh lén ngất, mất 25 khối Bổ Thiên thạch cùng 2 bình bảo đan, mọc cục u như sừng trên trán; tỉnh dậy đau đầu dữ dội, nhận ra kẻ tấn công là đứa nhỏ hắn từng đánh một chưởng để cướp Bổ Thiên thạch; sau đó lại bị đánh lén lần hai nện thẳng lên cục u chưa lành.","anchor":"Hắn lấy tay xoa xoa gáy, sau gáy giống như muốn nứt toát ra"},{"importance":"normal","chuong":"@c0107","tieuDe":"Khối u đầu bị đồn khắp giới","text":"Cả Hư Thần giới bàn tán liên hệ khối u to trên đầu hắn với hàng chữ trên tảng đá của nhóc tỳ; đã được chuyển đi vì biểu hiện kinh người ở chiến trường thứ hai; bên trong Bổ Thiên các nghe bàn tán suýt nổi khùng.","anchor":"Thiếu niên áo bào màu bạc trên đầu xuất hiện khối u thật lớn"},{"chuong":"@c0108","importance":"normal","tieuDe":"Một chiêu thắng rồi lộ tính kiêu","text":"Một chiêu ánh bạc cuốn bay nữ đệ tử; nghe tán thưởng thì cứng đờ nổi gân xanh cố nhịn kích động rồi rút lui; sau bị đám đệ tử mới bao vây hỏi.","anchor":"trên trán nổi lên gân xanh, hắn cố nhịn xuống kích động, chậm rãi rút lui"}],"tuViMoc":[],"tuVi":"Tu vi kinh người, được đám bại trận xem là số một trong hơn chín vạn người tham gia đợt kiểm tra (@c0101).","nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị Nhóc tỳ (Thạch Hạo) đánh lén một búa quật ngã; từng đánh lén đối phương một chưởng.","ghiChu":""},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị Nhóc tỳ đánh lén trả thù","ghiChu":"Tiêu Thiên từng đánh một chưởng cướp Bổ Thiên thạch của Nhóc tỳ, bị đánh lén báo thù 2 lần (@c0102)"},{"ten":"Cổ Ngạc","tag":"khac","quanHe":"Được nhắc qua bối cảnh Nhóc tỳ bị đuổi giết","ghiChu":"Nhóc tỳ từng bị Cổ Ngạc đuổi giết, khi ấy Tiêu Thiên đánh lén Nhóc tỳ (@c0102)"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị đồn là kẻ nện búa lên đầu","ghiChu":"@c0107"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Bảo đan","trangThai":"da-dung","moTa":"Nuốt một viên khôi phục trạng thái cường thịnh sau ác chiến.","nguon":"@c0101"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Bổ Thiên thạch","moTa":"Thu được 16 khối trong một đêm chinh chiến.","nguon":"@c0101"}]}},"nguon":["@c0101","@c0102","@c0107","@c0108"]},{"id":"thieu-nien-moc-toc","name":"Thiếu niên Mộc tộc","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Mộc tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiếu niên tộc Mộc rất mạnh tại chiến trường thứ hai, đến muộn vẫn thắng liên tiếp bảy trận nhưng cuối cùng bại dưới tay Tiêu Thiên.","vaiTro":"Cường giả phe Mộc tộc trong đợt kiểm tra, làm nền cho sức mạnh của Tiêu Thiên.","tinhCach":[{"text":"Kiêu dũng, hiếu chiến — đến muộn vẫn liên tiếp áp đảo đối thủ.","chuong":"@c0101"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0101","tieuDe":"Thắng bảy trận rồi bại dưới tay Tiêu Thiên","text":"Thiếu niên Mộc tộc rất mạnh, tuy đến muộn vẫn thắng liên tiếp bảy trận, nhưng cuối cùng thua Tiêu Thiên, toàn thân đầy máu bỏ chạy.","anchor":"còn chiến thắng liên tiếp bảy trận"}],"tuViMoc":[],"tuVi":"Tu vi rất mạnh, thắng liên tiếp bảy trận trước khi bại dưới tay Tiêu Thiên (@c0101).","nhanMach":[{"ten":"Tiêu Thiên","tag":"doi-thu","quanHe":"Bị Tiêu Thiên đánh bại sau bảy trận thắng liên tiếp.","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0101"]},{"id":"hung-phi-truong-lao","name":"Hùng Phi","aliases":["Hùng Phi trưởng lão"],"gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0102","tieuDe":"Nhượng bộ cho 3000 người thông qua","text":"Trưởng lão khu thứ tám, cùng Trác Vân trưởng lão và tộc lão các bộ lạc thương lượng sau bạo động khu thứ tám, cắn răng chấp nhận cho 3000 người trong hơn 8900 người thông qua, dự định tuyển chọn lại.","anchor":"cuối cùng đành phải cắn răng, thiếu chút nữa là rơi lệ, cho phép ba ngàn người thông qua"},{"chuong":"@c0103","importance":"normal","tieuDe":"Dụ nhóc tỳ vào chiến trường thứ hai","text":"Hằn học đòi tính sổ thằng ranh nhân thần cộng phẫn; nhấn mạnh đã tham gia thử luyện tức là đệ tử Bổ Thiên Các, dẫn ba nghìn đứa nhỏ vào chiến trường thứ hai xem lễ để không cho nhóc tỳ chạy; ngộ nhận Tiêu Thiên là kỳ tài.","anchor":"Đây tuyệt đối là một kỳ tài ngút trời, mười năm nay ít thấy"},{"importance":"normal","chuong":"@c0105","tieuDe":"Suy ra thủ phạm, tuyên bố kết thúc khảo nghiệm","text":"Là người đầu tiên suy đoán thủ phạm trộm bảo dược là nhóc siêu quậy, nhận thần niệm cảnh báo của Hắc hổ về kế điệu hổ ly sơn; ra lệnh phong tỏa chiến trường thứ hai bày thiên la địa võng truy đuổi, cuối cùng cùng Trác Vân tuyên bố khảo nghiệm kết thúc, mắt phát xanh dò xét đám thiên tài.","anchor":"Chậm rãi tìm kiếm, chỉ cần tiến vào Bổ Thiên các, không tin là tìm không ra!"},{"importance":"major","chuong":"@c0106","tieuDe":"Phát lệnh truy nã Nhóc siêu quậy","text":"Sau khi tảng đá Tế Linh mang chữ khiêu khích được đưa lên trước ba ngàn tân đệ tử, Hùng Phi trưởng lão trực tiếp phát lệnh truy nã Nhóc siêu quậy, treo thưởng ai tìm ra manh mối sẽ thành đệ tử trọng yếu nhất; sau đó cùng Trác Vân bất đắc dĩ nhận trăm môn đồ (bao gồm chính Thạch Hạo), do phạm lỗi nặng nên chủ động nhận việc nặng nhọc; giảng văn tự Hoàn Cốt cho tân đệ tử rồi vội rời đi.","anchor":"Hùng Phi trưởng lão lại trực tiếp phát ra một lệnh truy nã"},{"importance":"normal","chuong":"@c0107","tieuDe":"Phun máu truy nã nhóc tỳ","text":"Vì bị nhóc tỳ đào Bảo Cốt khu thứ tám, trộm Bảo Dược và lưu tảng đá, tức tới mức phun máu và cuối cùng phải phát lệnh truy nã đứa nhỏ."},{"importance":"normal","chuong":"@c0109","tieuDe":"Điều tra bất thành","text":"Cùng Trác Vân xuất hiện xử lý vụ xung đột, điều tra nhưng không ai nhận là kẻ cầm đầu; rít gào nửa canh giờ rồi thu hồi Khuyển Ma Công, căm giận rời đi.","anchor":"căn bản không có ai là người đẫn đầu gây chuyện, chỉ có mấy kẻ xui xẻo"}],"nhanMach":[{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Cùng là trưởng lão khu thứ tám","ghiChu":"Cùng thương lượng chuyện cho 3000 người thông qua sau bạo động (@c0102)"},{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Bổ Thiên Các","ghiChu":""},{"ten":"Nhóc tỳ","tag":"doi-thu","quanHe":"Đòi tính sổ, giăng bẫy bắt","ghiChu":""},{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Cùng là trưởng lão Bổ Thiên các, phối hợp truy lùng nhóc tỳ."},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Suy ra nhóc tỳ là thủ phạm và ra lệnh truy lùng."},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Đệ tử mới thu nhận (thực chất là Nhóc siêu quậy bị truy nã)","ghiChu":"@c0106"},{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Đồng trưởng lão Bổ Thiên các","ghiChu":"@c0107"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối tượng truy nã","ghiChu":"@c0107"}],"tuViMoc":[]},"nguon":["@c0102","@c0103","@c0105","@c0106","@c0107","@c0109"]},{"id":"trac-van-truong-lao","name":"Trác Vân","aliases":["Trác Vân trưởng lão"],"gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0102","tieuDe":"Quyết định nhượng bộ khu thứ tám","text":"Trưởng lão khu thứ tám, cùng Hùng Phi và tộc lão các bộ lạc quyết định nhượng bộ, cho phép 3000 người thông qua sau khi phù cốt bị cướp khiến trận vực mất hiệu lực.","anchor":"cuối cùng đành phải cắn răng, thiếu chút nữa là rơi lệ, cho phép ba ngàn người thông qua"},{"chuong":"@c0103","importance":"normal","tieuDe":"Khoe gốc thuốc chăm bằng Hắc Hổ Sát","text":"Nhấn mạnh không thông qua cũng cho thông qua để giữ chân nhóc tỳ; mời khách xem lễ, khoe gốc thuốc quý được chăm bằng Hắc Hổ Sát, tương lai có thể lột xác thành Thánh Dược, nhằm phô nội tình Bổ Thiên Các oai chấn tứ phương.","anchor":"Tới lúc cần thiết thì phải để lộ một phần nội tình của Bổ Thiên Các"},{"importance":"normal","chuong":"@c0105","tieuDe":"Phát điên vì mất Hắc Sát Liên","text":"Từ dáng vẻ hiền lành lịch sự chuyển sang điên cuồng gào thét chấn động thiên địa khi phát hiện Hắc Sát Liên trong địa quật biến mất; nhận ra Hắc hổ ra ngoài là kế điệu hổ ly sơn, sau đó phun máu khi biết nhóc tỳ đã ăn sống bảo dược; cùng Hùng Phi tuyên bố khảo nghiệm kết thúc để dò xét đám thiên tài.","anchor":"miệng mở thật rộng, điên cuồng gào thét không ngớt, làm cho thiên địa chấn động nổ vang"},{"importance":"normal","chuong":"@c0106","tieuDe":"Cùng Hùng Phi thu nhận trăm môn đồ","text":"Sai người mang tảng đá Tế Linh có chữ khiêu khích lên cho ba ngàn người xem; cùng Hùng Phi bất đắc dĩ nhận trăm môn đồ trong đó có Thạch Hạo (kẻ từng chọc mình đến hộc máu); chủ động nhận việc nặng nhọc do phạm lỗi nặng; giảng văn tự Hoàn Cốt rồi vội rời đi.","anchor":"đám nhỏ này do ta cùng Trác Vân mang đi"},{"importance":"normal","chuong":"@c0107","tieuDe":"Cùng truy nã nhóc tỳ","text":"Cùng Hùng Phi tức đến phun máu, tham gia truy nã nhóc tỳ sau các sự kiện đào Bảo Cốt và lưu tảng đá."},{"importance":"normal","chuong":"@c0109","tieuDe":"Điều tra vụ xung đột","text":"Cùng Hùng Phi xuất hiện điều tra vụ đánh hội đồng nhưng không tìm ra kẻ cầm đầu, chỉ có mấy kẻ xui xẻo bị thương nặng; chỉ vào Chu Vũ Hào chửi mắng xối xả, tức giận, sau đó rít gào rồi thu hồi Khuyển Ma Công.","anchor":"căn bản không có ai là người đẫn đầu gây chuyện, chỉ có mấy kẻ xui xẻo"}],"nhanMach":[{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Cùng là trưởng lão khu thứ tám","ghiChu":"Cùng thương lượng chuyện nhượng bộ 3000 người (@c0102)"},{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Đồng liêu trưởng lão Bổ Thiên Các","ghiChu":""},{"ten":"Nhóc tỳ","tag":"doi-thu","quanHe":"Cùng bày bẫy giữ chân nhóc tỳ","ghiChu":""},{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Cùng là trưởng lão Bổ Thiên các, phối hợp truy lùng nhóc tỳ."},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Nhóc tỳ trộm và ăn sống Hắc Sát Liên khiến ông phun máu."},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Đệ tử mới thu nhận","ghiChu":"@c0106"},{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Đồng trưởng lão Bổ Thiên các","ghiChu":"@c0107"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối tượng truy nã","ghiChu":"@c0107"}],"tuViMoc":[]},"nguon":["@c0102","@c0103","@c0105","@c0106","@c0107","@c0109"]},{"id":"tiêu-thiên-thieu-nien-ao-bac","name":"Tiêu Thiên","cn":"","aliases":["Thiếu niên áo bạc"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên Các","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thiếu niên áo bạc tự nhận “đệ nhất thiên tài”, bị nhóc tỳ đập búa ngất rồi cướp Bổ Thiên Thạch; tỉnh dậy trong khe đá, nổi điên rống chấn động sơn hà nên bị các trưởng lão Bổ Thiên Các ngộ nhận là kỳ tài.","vaiTro":"Nạn nhân của nhóc tỳ, bị hiểu lầm thành kỳ tài","tinhCach":[{"text":"Kiêu ngạo, tự nhận là đệ nhất thiên tài","chuong":"@c0103"},{"text":"Phẫn uất, dễ nổi điên khi bị chèn ép","chuong":"@c0103"}],"tabs":{"diem":[{"text":"Tự nhận đệ nhất thiên tài nhưng bị nhóc tỳ đánh lén ngất, trán mọc cục u một sừng","chuong":"@c0103"}],"kinhLich":[{"chuong":"@c0103","importance":"major","tieuDe":"Tỉnh dậy được trả lại Bổ Thiên Thạch","text":"Tỉnh sau khi bị đập búa ngất cả đêm, kẹt trong khe đá bị bịt kín; phát hiện trong ngực và túi da thú có hơn hai mươi mấy viên Bổ Thiên Thạch được kẻ cướp trả lại, phẫn uất vì vẫn bị gõ thêm một búa cho ngất; rồi nổi điên rống chấn động sơn hà, toàn thân giăng phù văn màu bạc khiến các thiếu niên gần đó kinh hãi vì khí thế Âm Ba Công.","anchor":"đếm cẩn thận thì thấy có những hai mươi mấy viên"},{"chuong":"@c0103","importance":"normal","tieuDe":"Bị ngộ nhận thành kỳ tài","text":"Các trưởng lão Bổ Thiên Các nghe tiếng rống chấn động sơn hà, dồi dào trung khí liền ngộ nhận hắn là kỳ tài ngút trời hiếm thấy, khen ngợi không ngớt, các thế lực khác nảy ý tranh cướp; hắn soi mặt qua nước hồ thấy trên trán lồi một cục u to như sừng do hai búa trúng cùng một chỗ, hận đến ứa nước mắt.","anchor":"Hai phát búa vào cùng một chỗ đã cho ra đời một cường giả một sừng"}],"tuViMoc":[],"nhanMach":[{"ten":"Nhóc tỳ","tag":"doi-thu","quanHe":"Kẻ đánh lén hắn ngất, cướp rồi trả lại Bổ Thiên Thạch","ghiChu":"Bị nhóc tỳ gõ búa hai lần trúng cùng một chỗ, không cho nhìn mặt"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Âm Ba Công","moTa":"Công lực của Tiêu Thiên; khi hắn rống, chấn động sơn hà, đủ sức quét ngang các thiếu niên gần đó khiến họ kinh hãi.","nguon":"@c0103"}],"linhThu":[],"nguyenLieu":[{"ten":"Bổ Thiên Thạch","moTa":"Hơn hai mươi mấy viên tìm lại trong ngực và túi da thú sau khi bị cướp rồi trả.","nguon":"@c0103"}],"linhThao":[],"khac":[]}},"nguon":["@c0103"]},{"id":"thach-nghi","name":"Thạch Nghị","aliases":["Nghị nhi"],"gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0105","tieuDe":"Chờ nghi thức nhập môn Bổ Thiên các","text":"Đứng đợi trong sơn môn Bổ Thiên các cùng nhóm thiếu niên quyền quý để cùng trải qua nghi thức nhập môn; kỷ lục của hắn ở Hư Thần Giới bị nhóc tỳ phá, được dự báo sẽ có đối thủ về sau.","anchor":"còn có một đám thiếu niên đang đứng đợi, có Thạch Nghị"},{"importance":"minor","chuong":"@c0107","tieuDe":"Được tính lôi kéo đối phó Vũ tộc","text":"Nhóc tỳ nghi bọn bắt nạt Thanh Phong dựa vào Vũ gia Thạch Quốc nên tính kéo Thạch Nghị vào cuộc trừng trị."},{"importance":"normal","chuong":"@c0109","tieuDe":"Bước trên con đường Thượng Cổ Thánh Viện","text":"Được Thạch Hạo nhìn thấy đang bước trên con đường không tận cùng dẫn vào Thượng Cổ Thánh Viện, cộng hưởng cùng đại đạo, đi nhiều ngày mà không tới cuối; là tồn tại gần như thần trong các sinh linh cùng tuổi, được lợi ích to lớn dù chưa bước vào Thánh Viện.","anchor":"hắn đi trên trên con đường đó, tuy rằng vẫn không có bước vào Thượng Cổ Thánh Viện, thế nhưng như vậy cũng có thể được lợi ích to lớn"},{"importance":"normal","chuong":"@c0112","tieuDe":"Được nêu là kỳ tài dự tuyển Bách Đoạn sơn","text":"Được nêu tên như một trong các kỳ tài của Thượng Cổ Thánh Viện mà Bổ Thiên các định phái đi Bách Đoạn sơn tranh cơ duyên.","anchor":"hiện nay nơi đó có cơ duyên lớn"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Kẻ phá kỷ lục của hắn ở Hư Thần Giới, được dự báo thành đối thủ tương lai."},{"ten":"Thạch Hạo","tag":"ho-hang","quanHe":"Người thân được nhóc tỳ tính nhờ giúp","ghiChu":"@c0107"},{"ten":"Thạch Hạo","tag":"ho-hang","quanHe":"Người thân cùng bộ; được Thạch Hạo dõi theo trên con đường Thánh Viện","ghiChu":"@c0109"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0105","@c0107","@c0109","@c0112"]},{"id":"hac-ho-cu-thu","name":"Hắc hổ","aliases":[],"gioiTinh":"khong-ro","trangThai":"song","blurb":"Cự thú khổng lồ đen nhánh trong địa quật Bổ Thiên các, từng chinh chiến với Thái cổ dị chủng.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0105","tieuDe":"Xuất hiện, báo kế điệu hổ ly sơn","text":"Cự thú thân cao hơn ngọn núi, toàn thân đen nhánh có huyết mâu to lớn, từng chinh chiến với Thái cổ dị chủng, năm xưa một tiền bối cực mạnh phá bảo cụ hao tâm mới hàng phục được; từ địa quật đi ra tỏa sát khí đen cuồn cuộn, truyền thần niệm cho Hùng Phi báo đây là kế điệu hổ ly sơn rồi chậm rãi lui vào địa quật biến mất.","anchor":"đây là một con cự thú có thể chinh chiến với Thái cổ dị chủng"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Hùng Phi","tag":"khac","quanHe":"Truyền thần niệm cho Hùng Phi báo kế điệu hổ ly sơn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0105"]},{"id":"thieu-nu-ao-trang-bo-thien-cac","name":"Thiếu nữ áo trắng","aliases":["Sư tỷ áo trắng"],"gioiTinh":"nu","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Sư tỷ Bổ Thiên các dẫn dắt tân đệ tử","tabs":{"diem":[{"text":"Nữ tử áo trắng khoảng 18-19 tuổi, thích nhéo má trêu tân đệ tử","chuong":"@c0106"}],"kinhLich":[{"importance":"normal","chuong":"@c0106","tieuDe":"An trí và răn dạy trăm tân đệ tử","text":"Đến dẫn nhóm đi gặp sư phụ, nhéo má trêu Thạch Hạo và kinh ngạc vì độ lém của nó; sau khi Thạch Hạo được Hùng Phi và Trác Vân chọn, nàng nhéo má thêm quở trách đừng nói nhiều, bảo được hai trưởng lão dạy bảo là phúc khí; dẫn trăm tân đệ tử tới cùng núi, giảng quy củ và nghiêm khắc khuyên tuyệt đối đừng đi tới Tế Cư của Tế Linh.","anchor":"có thể được hai vị trưởng lão dạy bảo đó chính là phúc khí của các ngươi"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Tân đệ tử được nàng dẫn dắt, thường bị nhéo má","ghiChu":"@c0106"}],"tuiDo":{}},"nguon":["@c0106"]},{"id":"thieu-nien-ao-bao-mau-bac","name":"Thiếu niên áo bào màu bạc","gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Tân đệ tử Bổ Thiên các, nghi từng bị Nhóc siêu quậy chọc phá","tabs":{"diem":[{"text":"Phẫn nộ nghiến răng nổi gân xanh khi nhận ra chữ khiêu khích của Nhóc siêu quậy","chuong":"@c0106"}],"kinhLich":[{"importance":"normal","chuong":"@c0106","tieuDe":"Nhận ra thủ phạm khi thấy chữ trên tảng đá","text":"Đứng trong ba ngàn tân đệ tử, khi tảng đá Tế Linh với chữ 「Nắm Búa Nơi Tay, Ta Có Thiên Hạ」 được đưa lên, thiếu niên áo bào màu bạc lập tức nhận ra là bút tích của Nhóc siêu quậy, phẫn nộ nghiến răng, nổi gân xanh.","anchor":"Nắm Búa Nơi Tay, Ta Có Thiên Hạ"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Nghi từng bị Nhóc siêu quậy chọc phá, phẫn nộ khi nhận ra thủ phạm","ghiChu":"@c0106"}],"tuiDo":{}},"nguon":["@c0106"]},{"id":"lao-nhan-tang-da-xanh-bo-thien-cac","name":"Lão nhân trên tảng đá xanh","gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Cao nhân Bổ Thiên các quyết định thu nhận tân đệ tử","tabs":{"diem":[{"text":"Ánh mắt phảng phất cảnh khai thiên tích địa, cao thâm khó lường","chuong":"@c0106"}],"kinhLich":[{"importance":"normal","chuong":"@c0106","tieuDe":"Đau đầu vì đợt nhập môn quá đông","text":"Ngồi xếp bằng trên tảng đá xanh nhức đầu vì đợt này số qua khảo nghiệm còn ba ngàn người (thường chỉ vài trăm mỗi năm); mắt phảng phất cảnh khai thiên tích địa, quyết định vẫn thu nhận thêm môn đồ.","anchor":"Dẫn về gần chín vạn thiếu niên không có thông qua được khảo nghiệm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0106"]},{"id":"thanh-phong","name":"Thanh Phong","gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Tiểu đệ tu vi yếu nhất thiên tài doanh, bị đánh bầm nửa người và cấy Phù Văn phá tu hành.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0107","tieuDe":"Bị bắt nạt trong thiên tài doanh","text":"Ngồi một mình trong nhà gỗ tự xử lý vết thương, mặt sưng húp có khối máu đọng; bị bọn thiếu niên thiên tài đánh bầm nửa người, cấy Phù Văn chạy loạn trong vết thương nhằm phá tu hành để đào thải khỏi thiên tài doanh; quyết cắn răng kiên trì tới đầu tháng lấy Dược Tán và Cốt Thư, đồng thời ghi nhớ kinh văn Tế Linh giúp tiểu ca ca; ngăn Bóng Lông đi báo thù vì sợ lộ.","anchor":"một số Phù Văn ở bên trong vết thương chạy loạn"},{"chuong":"@c0108","importance":"normal","tieuDe":"Bị Chu Vũ Hào ám toán trọng thương","text":"Bị Chu Vũ Hào ép diễn võ rồi dùng Ngư Long Phù Văn đánh bay, ngũ tạng như bể nát; sau bị hắn mượn cớ khơi thông huyết mạch hại thêm, hất vào rừng trúc; mắt đầy lửa giận nhưng không dám phát tác, siết nắm đấm trắng bệch.","anchor":"chỉ biết siết chặc nắm đấm đến nỗi năm ngón tay đều trắng bệch ra"},{"importance":"normal","chuong":"@c0109","tieuDe":"Kinh ngạc trước phong ba do tiểu ca ca gây ra","text":"Được Thạch Hạo bảo vệ trong loạn, kinh ngạc khi biết toàn bộ phong ba đẫm máu là do một tay tiểu ca ca gây ra, miệng tròn như quả trứng; được Thạch Hạo nháy mắt tươi vui.","anchor":"đó là chí bảo của Bổ Thiên các chúng ta, do Tế Linh kết ra"},{"importance":"normal","chuong":"@c0113","tieuDe":"Nhận gói linh dược từ nhóc tỳ","text":"Thanh Phong là đệ tử Thiên tài doanh, được nhóc tỳ gọi là đệ đệ; mở gói thấy một cây linh dược nguyên vẹn nên kinh sợ tưởng đồ trộm từ vườn thuốc, vì đệ tử thiên tài cũng chỉ được dùng Dược tán; đám đông xem thường nhóc tỳ vì Thanh Phong thực lực không mạnh, thậm chí chưa vào được Thiên tài doanh.","anchor":"Hắn chính là đệ đệ của ta, ta đến để đưa thuốc cho hắn"},{"importance":"normal","chuong":"@c0114","tieuDe":"Được ca ca bảo vệ, khích lệ tu hành","text":"Ở Thiên tài doanh, nhỏ tuổi hơn người khác nên bị bắt nạt; được nhóc tỳ (ca ca) công khai bảo vệ, khích lệ học theo đánh ngã kẻ bắt nạt và yên tâm tu hành khi ca ca lên đường đi Bách Đoạn sơn.","anchor":"Thanh Phong chính là đệ đệ của ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Tiểu ca ca thân thiết","ghiChu":"@c0107"},{"ten":"Bóng Lông","tag":"dong-minh","quanHe":"Bạn đồng hành lén tới thăm","ghiChu":"@c0107"},{"ten":"Chu Vũ Hào","tag":"doi-thu","quanHe":"Kẻ ức hiếp ám toán","ghiChu":""},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Sư huynh (nhóc tỳ) bảo vệ","ghiChu":"Nhóc tỳ gài Chu Vũ Hào để trả thù cho Thanh Phong"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Được Thạch Hạo bảo vệ trong xung đột","ghiChu":"@c0109"},{"ten":"Thạch Hạo","tag":"ho-hang","quanHe":"Được nhóc tỳ gọi là đệ đệ, nhận gói linh dược","ghiChu":"@c0113"},{"ten":"Thạch Hạo","tag":"ho-hang","quanHe":"Ca ca","ghiChu":"Ca ca bảo vệ và khích lệ tu hành (@c0114)."}],"tuiDo":{}},"nguon":["@c0107","@c0108","@c0109","@c0113","@c0114"]},{"id":"bong-long","name":"Bóng Lông","gioiTinh":"khong-ro","theLuc":[],"trangThai":"song","blurb":"Con vật nhỏ đồng hành cùng Thạch Hạo, giỏi lang thang Linh sơn hái linh dược.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0107","tieuDe":"Trở về báo tin cho nhóc tỳ","text":"Sau nhiều ngày vắng mặt, Bóng Lông tìm tới phòng nhóc tỳ, bị tóm đuôi; trên móng vuốt còn mùi linh dược vì lang thang Linh sơn nguy hiểm mới hái được một cây linh thảo, coi là sỉ nhục nên tức giận; được sai đi điều tra Thanh Phong, lén thăm rồi về báo tin sau nửa đêm.","anchor":"nhanh chóng nắm chặt lấy đuôi của Bóng Lông"},{"importance":"bridge","chuong":"@c0111","tieuDe":"","text":"Sợ hãi trốn sau lưng Thạch Hạo, nắm cổ áo như gấu túi khi ông lão tử khí xuất hiện.","anchor":""}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"dong-minh","quanHe":"Chủ nhân/bạn đồng hành","ghiChu":"@c0107"},{"ten":"Thanh Phong","tag":"dong-minh","quanHe":"Bạn nhỏ được lén thăm","ghiChu":"@c0107"}],"tuiDo":{"linhThao":[{"ten":"Linh thảo Linh sơn","moTa":"Một cây linh thảo Bóng Lông hái được trên Linh sơn/Bảo Sơn khí lành, nguy hiểm mới lấy được.","nguon":"@c0107"}]}},"nguon":["@c0107","@c0111"]},{"id":"vu-phong","name":"Vũ Phong","cn":"","aliases":["Bạch y Vũ Phong","Thiếu niên áo trắng"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiên tài áo trắng cao gầy, khí chất như ngọc, cường giả nổi danh từng đánh bại hơn mười cường giả vây công, có muội muội tên Vũ Lâm.","vaiTro":"Sư huynh thiên tài doanh, kêu gọi hòa khí giữa các đệ tử","tinhCach":[{"text":"Ôn hòa, khí chất như ngọc, mỉm cười nói chuyện, kêu gọi không tổn thương hòa khí"}],"tabs":{"diem":[{"text":"Cường giả nổi danh từng dẫn sấm sét, phù văn vàng đánh tan hơn mười cường giả vây công","chuong":"@c0108"}],"kinhLich":[{"chuong":"@c0108","importance":"normal","tieuDe":"Ra mặt kêu gọi hòa khí","text":"Tự giới thiệu với đệ tử mới, nhấn mạnh tu hành có trước sau nhưng không phân địa vị cao thấp; đồng ý tha Thanh Phong khi bị Chu Vũ Hào ức hiếp; bị nhóm thiếu nữ vây quanh thỉnh giáo đông nhất.","anchor":"Ta tên Vũ Phong, nhập môn sớm hơn mọi người mấy năm"},{"importance":"normal","chuong":"@c0109","tieuDe":"Muốn ngăn cản nội chiến","text":"Muốn ngăn cản cuộc xung đột quy mô lớn giữa đệ tử mới và thiên tài doanh nhưng biết chắc không có tác dụng khi hơn ba ngàn người dùng Phù Văn đối kháng.","anchor":"người kêu gào đầu tiên tự nhiên là nó"},{"importance":"normal","chuong":"@c0114","tieuDe":"Từ chối xuất thủ áp chế nhóc tỳ","text":"Cường giả áo trắng trong Thiên tài doanh, được người khác giục ra tay áp chế nhóc tỳ nhưng lắc đầu không xuất thủ, chỉ có tinh quang lóe trong mắt và chắp tay sau lưng — ám chỉ cường giả tiềm ẩn.","anchor":"Bạch y Vũ Phong lắc đầu, vẫn không xuất thủ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vũ Lâm","tag":"ho-hang","quanHe":"Muội muội","ghiChu":"Thiếu nữ thiên tài kiều diễm mỹ lệ"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Cường giả quan sát","ghiChu":"Không ra tay với nhóc tỳ, chỉ lóe tinh quang (@c0114)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0108","@c0109","@c0114"]},{"id":"vu-lam","name":"Vũ Lâm","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Muội muội của Vũ Phong, thiếu nữ thiên tài kiều diễm mỹ lệ.","vaiTro":"Thiếu nữ thiên tài, muội muội Vũ Phong","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0108","importance":"minor","tieuDe":"Được nhắc tên","text":"Được nhắc là muội muội của Vũ Phong, cũng là thiếu nữ thiên tài kiều diễm.","anchor":"Ta tên Vũ Phong, nhập môn sớm hơn mọi người mấy năm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vũ Phong","tag":"ho-hang","quanHe":"Huynh trưởng","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0108"]},{"id":"chu-vu-hao","name":"Chu Vũ Hào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiên tài da màu cổ đồng, mắt có Phù Văn, giả bộ sư huynh ôn hòa nhưng ám toán đánh trọng thương Thanh Phong, sau bị nhóc tỳ gài bẫy truy sát.","vaiTro":"Thiên tài Bổ Thiên các, kẻ ức hiếp Thanh Phong","tinhCach":[{"text":"Giả nhân giả nghĩa, ngoài mặt ôn hòa nhưng lén dùng ám kình hại người yếu hơn"},{"text":"Miệng nhanh hơn não, tự chuốc họa vì nói linh tinh"}],"tabs":{"diem":[{"text":"Giả bộ sư huynh tốt nhưng dùng ám kình đánh trọng thương Thanh Phong, sau bị nhóc tỳ gài cho mấy trăm người đuổi đánh","chuong":"@c0108"}],"kinhLich":[{"chuong":"@c0108","importance":"normal","tieuDe":"Ám toán Thanh Phong rồi bị gài truy sát","text":"Ép Thanh Phong diễn võ, dùng Ngư Long Phù Văn kèm ám kình đánh nó bay ngã ngũ tạng như bể nát; sau mượn cớ khơi thông huyết mạch hại thêm lần nữa; rồi bị nhóc tỳ đấm nở hoa mặt, vu là đồng bọn nhóc siêu quậy, mấy trăm đệ tử mới đuổi đánh đến răng bay hộc máu chạy trối chết.","anchor":"Một con Ngư Long phát sáng đánh nó bay ra ngoài"},{"importance":"normal","chuong":"@c0109","tieuDe":"Bị đánh hội đồng tàn phế","text":"Bị mấy trăm rồi hơn ngàn thiếu niên các bộ lạc đánh hội đồng vì trước đó tuyên bố biết chỗ nhóc siêu quậy; bị Phù Chưởng thần bí đánh gãy xương sườn trái, ngã xuống bị biển người giẫm đạp, gãy hết răng, gãy chín phần mười xương cốt, tàn phế, cần mấy tháng điều dưỡng bằng Dược Tán.","anchor":"Toàn bộ hàm răng của hắn đều bị đánh bay, bị mọi người vừa đạp vừa đánh khiến toàn thân vô lực."},{"importance":"normal","chuong":"@c0114","tieuDe":"Bị đấm gục, nhận ra thân phận nhóc tỳ","text":"Đang bị thương (từng suýt bị giẫm chết trong xung đột đẫm máu trước, nhờ Bảo Dược của tộc mới bình phục), Chu Vũ Hào núp trong đám người chỉ đặt cược ít; bị nhóc tỳ chủ động đấm một quyền vào mặt, trước khi hôn mê nhận ra cú đấm quen thuộc và hiểu ra nhóc tỳ chính là ca ca của Thanh Phong.","anchor":"nó chính là ca ca của Thanh Phong"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Phong","tag":"doi-thu","quanHe":"Đệ tử bị hắn ức hiếp","ghiChu":"Cùng hai thiên tài khác từng đánh Thanh Phong"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị nhóc tỳ gài bẫy truy sát","ghiChu":""},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị Thạch Hạo giật dây đánh hội đồng, một quyền của hắn khiến mặt nở hoa","ghiChu":"@c0109"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Cựu thù","ghiChu":"Bị nhóc tỳ đấm gục, nhận ra là ca ca của Thanh Phong (@c0114)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Ngư Long Phù Văn","moTa":"Phù Văn hóa Ngư Long phát sáng, kèm ám kình","nguon":"@c0108"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0108","@c0109","@c0114"]},{"id":"ong-lao-cam-ho-lo-vo-vang","name":"Ông lão cầm hồ lô vỏ vàng","aliases":["Ông lão ngồi trước sơn môn","Lão tiền bối cầm hồ lô vàng","Ông lão cầm hồ lô vỏ vàng"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cao tầng Bổ Thiên các ngồi trước sơn môn, dùng hồ lô vỏ vàng nuốt hết bão táp dẹp loạn cuộc nội chiến.","vaiTro":"Cao tầng Bổ Thiên các","tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0109","tieuDe":"Dùng hồ lô vỏ vàng dẹp loạn","text":"Từ hư không thả ra một hồ lô vỏ vàng nuốt hết bão táp mãnh liệt đủ hủy diệt vùng núi như cá voi hút nước; hồ lô thu nhỏ bằng lòng bàn tay rơi vào tay ông; ông ra lệnh người dẫn đầu gây chuyện diện bích ba năm rồi vung tay áo rời đi.","anchor":"một cái hồ lô vỏ vàng từ trong hư không xuất hiện, màu vàng óng, toả ra hi quang, sau đó giống như là cá voi hút nước, nuốt hết tất cả bão táp mãnh liệt"},{"importance":"normal","chuong":"@c0112","tieuDe":"Giải chân tướng Tử Thần cho nhóc tỳ","text":"Cầm hồ lô vàng óng tràn khí Hỗn Độn dẫn đám trưởng lão tới giải cứu nhóc tỳ; giải thích vị thần quái xưng Tử Thần cách mấy trăm năm xuất thế một lần, thanh kiếm cắm đầu Hắn là của đối thủ ngày xưa còn kiếm thật rơi mất ở Bách Đoạn sơn mạch; nêu Bổ Thiên các định phái kỳ tài đi Bách Đoạn sơn tranh cơ duyên lớn, nếu Tử Thần chọn nhóc tỳ thì các thêm một suất.","anchor":"chúng ta không muốn thanh kiếm này, mà là tới giải cứu cháu"}],"nhanMach":[]},"nguon":["@c0109","@c0112"]},{"id":"tu-than","name":"Tử Thần","aliases":["Ông lão tóc xám","Ông lão tử khí","U linh Thượng Cổ","Ông lão tóc xám (u linh Thượng Cổ)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (tồn tại tử khí Thượng Cổ) @c0111","trangThai":"khong-ro","blurb":"Tồn tại tử khí thời Thượng Cổ, tóc xám nhuốm máu đen khô cứng, y phục Thượng Cổ, một cổ kiếm rỉ sét cắm trên đầu, mắt trống rỗng; liên tục cản đường Thạch Hạo đòi trả kiếm.","vaiTro":"U linh Thượng Cổ bám theo Thạch Hạo","tinhCach":[{"text":"Cố chấp lặp đi lặp lại lời đòi trả kiếm, tái tạo từ hư không mỗi khi bị né tránh","chuong":"@c0111"}],"tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0111","tieuDe":"U linh Thượng Cổ đòi kiếm","text":"Xuất hiện tại nơi ở Tế Linh với tử khí không sự sống, cổ kiếm cắm đầu, liên tục cản đường Thạch Hạo và lặp lại lời đòi trả kiếm; chỉ Thạch Hạo nhìn thấy còn người khác chỉ sờ được như tượng băng; sau lời hứa trả kiếm thì biến mất giữa sấm chớp rồi xuất hiện lại lần hai náo loạn đệ tử.","anchor":"cảm giác sờ tới một bức tượng băng, lạnh giá thấu xương"},{"importance":"major","chuong":"@c0112","tieuDe":"Chân tướng Tử Thần chọn người phải chết","text":"Vị tồn tại thần quái Thượng Cổ bị cổ kiếm đâm xuyên đầu, xưng Tử Thần, cách mấy trăm năm xuất thế một lần cùng dịp Bách Đoạn sơn mở ra; phàm người bị Hắn chọn trúng đa số là thiên tài đều chết, lần này lại chọn một đệ tử bình thường là nhóc tỳ khiến cả đám kinh ngạc; thanh kiếm cắm đầu Hắn là của đối thủ cũ, kiếm thật của Hắn rơi mất ở Bách Đoạn sơn.","anchor":"phàm là người bị hắn chọn trúng đều chết hết, không có một người sống sót"}],"nhanMach":[{"ten":"Thạch Hạo","tag":"khac","quanHe":"Cản đường đòi trả kiếm; được Thạch Hạo hứa tìm giúp trả kiếm rồi bị cưỡi lên cổ","ghiChu":"@c0111"},{"ten":"Thạch Hạo","tag":"khac","quanHe":"Chọn trúng nhóc tỳ (đệ tử bình thường) thay vì thiên tài","ghiChu":"@c0112"}],"tuiDo":{}},"nguon":["@c0111","@c0112"]},{"id":"hung-phi","name":"Hùng Phi","aliases":["Hùng Phi trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c0111","trangThai":"song","blurb":"Trưởng lão Bổ Thiên các gần Linh Sơn; nghe báo náo quỷ thì biến sắc, run rẩy bỏ chạy đi mời lão tiền bối.","vaiTro":"Trưởng lão Bổ Thiên các","tinhCach":[{"text":"Kinh sợ trước hiện tượng thần quái Thượng Cổ, bỏ chạy trối chết","chuong":"@c0111"}],"tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0111","tieuDe":"Biến sắc bỏ chạy vì náo quỷ","text":"Nghe đệ tử báo có náo quỷ tại khu nhà đệ tử mới thì biến sắc, cùng Trác Vân run rẩy bỏ chạy đi mời lão tiền bối.","anchor":"cứ cách mấy trăm năm xuất hiện một lần, phàm là xuất hiện, tất nhiên sẽ chết không ít người"},{"importance":"normal","chuong":"@c0112","tieuDe":"Bị nhóc tỳ bám cổ suýt ngất","text":"Trưởng lão bối phận kém của Bổ Thiên các, bị nhóc tỳ nhảy lên bám cổ ôm không buông suýt bóp tắt thở, nhờ Phù Văn trên người mới không xỉu, phải đi thụt lùi dẫn nhóc tỳ tới cung điện vì có thi thể cổ đứng trước mặt; chợt nghi ra thân phận nhóc tỳ khi thấy nó còn đáng ghét hơn thằng nhóc ở Hư Thần giới.","anchor":"so với thằng nhóc ở Hư Thần giới còn đáng ghét hơn"},{"importance":"normal","chuong":"@c0113","tieuDe":"Nhận ra thằng nhóc quỷ gây loạn","text":"Hùng Phi chợt nhận ra nhóc tỳ chính là thằng nhóc quỷ từng gây loạn khiến hắn và Trác Vân khốn đốn, uất ức nhưng không dám cãi lão tiền bối; sau đó bắt gặp nó gặm Tuyết Ngọc Sâm và tố nó ăn trộm.","anchor":"Ngươi... Ngươi chính là thằng nhóc quỷ kia?!"}],"nhanMach":[{"ten":"Trác Vân","tag":"su-mon","quanHe":"Cùng là trưởng lão Bổ Thiên các, cùng bỏ chạy đi mời lão tiền bối","ghiChu":"@c0111"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Đệ tử mới gây náo loạn khiến ông biến sắc bỏ chạy","ghiChu":"@c0111"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Bị nhóc tỳ bám cổ suýt ngất, nghi ra thân phận","ghiChu":"@c0112"},{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Cùng trưởng lão Bổ Thiên các hộ tống nhóc tỳ","ghiChu":"@c0112"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Nhận ra nó là kẻ gây loạn khiến mình khốn đốn, tố nó trộm linh dược","ghiChu":"@c0113"},{"ten":"Trác Vân","tag":"dong-minh","quanHe":"Cùng khốn đốn vì nhóc tỳ gây loạn","ghiChu":"@c0113"}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c0111","@c0112","@c0113"]},{"id":"trac-van","name":"Trác Vân","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c0111","trangThai":"song","blurb":"Trưởng lão Bổ Thiên các gần Linh Sơn; tiết lộ chuyện thần quái Thượng Cổ cách mấy trăm năm xuất hiện một lần tất chết người rồi bỏ chạy.","vaiTro":"Trưởng lão Bổ Thiên các","tinhCach":[{"text":"Hiểu biết chuyện thần quái Thượng Cổ, kinh sợ bỏ chạy đi mời lão tiền bối","chuong":"@c0111"}],"tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0111","tieuDe":"Tiết lộ thần quái Thượng Cổ","text":"Cùng Hùng Phi nghe báo náo quỷ, tiết lộ hiện tượng thần quái này có từ Thượng Cổ, cứ cách mấy trăm năm xuất hiện một lần tất chết người, rồi bỏ chạy đi mời lão tiền bối.","anchor":"cứ cách mấy trăm năm xuất hiện một lần, phàm là xuất hiện, tất nhiên sẽ chết không ít người"},{"importance":"normal","chuong":"@c0112","tieuDe":"Kể truyền thuyết thần quái Thượng Cổ","text":"Trưởng lão bối phận kém của Bổ Thiên các, người kể cho nhóc tỳ về truyền thuyết vị thần quái Thượng Cổ mỗi lần xuất hiện đều có một đám người phải chết đa số là thiên tài, bị nhóc tỳ bám trước rồi mới chuyển sang Hùng Phi.","anchor":"phàm là người bị hắn chọn trúng đều chết hết, không có một người sống sót"}],"nhanMach":[{"ten":"Hùng Phi","tag":"su-mon","quanHe":"Cùng là trưởng lão Bổ Thiên các, cùng bỏ chạy đi mời lão tiền bối","ghiChu":"@c0111"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Đệ tử mới gây náo loạn khiến ông biến sắc bỏ chạy","ghiChu":"@c0111"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Kể truyền thuyết Tử Thần, bị nhóc tỳ bám","ghiChu":"@c0112"},{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Cùng trưởng lão Bổ Thiên các","ghiChu":"@c0112"}],"tuiDo":{}},"nguon":["@c0111","@c0112"]},{"id":"dao-da","name":"Đào Dã","aliases":["Lão tiền bối cầm hồ lô vàng","Ông lão cầm hồ lô vỏ vàng","Lão quái vật","Nguyên lão Bổ Thiên các"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0113","tieuDe":"Ép nhóc tỳ đi Bách Đoạn sơn","text":"Đào Dã cầm đầu nhóm nguyên lão, giọng ôn hòa; dọa nếu nhóc tỳ không đi Bách Đoạn sơn thì Hắn không đáp ứng và nó sớm muộn mất mạng vì mang Tang thần bên người; cho Hùng Phi dẫn nó xuống bàn bạc; sau vụ trộm Tuyết Ngọc Sâm thì bất đắc dĩ dặn canh chừng, cấm nó lại gần vườn thuốc, hứa lần sau cho hẳn một sọt củ cải thật.","anchor":"sau này không có phép nó đến gần vườn thuốc nữa"},{"importance":"normal","chuong":"@c0114","tieuDe":"Báo tin các dòng dõi đỉnh cấp đến Bách Đoạn sơn","text":"Đào Dã cho biết Thạch Nghị, con gái Nhân hoàng cùng hậu duệ Thái cổ di chủng đã được tộc nhân hộ tống đến Bách Đoạn sơn mạch từ trước, đặt sân khấu cho tuyến truyện với các dòng dõi đỉnh cấp.","anchor":"còn có hậu duệ của Thái cổ di chủng nữa"},{"importance":"normal","chuong":"@c0115","tieuDe":"Dẫn đội tới Đoạn Không thành, dằn mặt phu xe Tây Lăng","text":"Đào Dã dẫn đội hộ tống nhóc tỳ (tiểu sư đệ) và năm thiếu niên thiên tài qua con đường Thanh Kim vào Đoạn Không thành; khi tiểu Bạch Hổ muốn ăn thịt nữ đệ tử, ông lấy ra hồ lô vàng lưu chuyển Phù Văn, xưng danh Bổ Thiên các để dằn mặt phu xe Tây Lăng thú sơn.","anchor":"chúng ta tới từ Tây Lăng thú sơn"},{"importance":"normal","chuong":"@c0117","tieuDe":"Hộ tống nhóm thiên tài vào Bách Đoạn Sơn","text":"Dẫn nhóm thiên tài Bổ Thiên các nhập Bách Đoạn Sơn, nhiều lần bị Nhóc Tỳ chọc tức đỏ mặt rồi đen sạm vì trò “trưng dụng nhà bếp” bôi nhọ danh Bổ Thiên các; lời dặn về các thông đạo được sư huynh nhắc lại cho cả nhóm.","anchor":"bọn họ đã đi qua cửa để tiến vào trong một thông đạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"khac","quanHe":"Lão tiền bối ép nó đi Bách Đoạn sơn, bị nó lừa lấy Tuyết Ngọc Sâm","ghiChu":"@c0113"},{"ten":"Hùng Phi","tag":"dong-minh","quanHe":"Sai Hùng Phi dẫn và canh chừng nhóc tỳ","ghiChu":"@c0113"},{"ten":"Thạch Hạo","tag":"an-nhan","quanHe":"Báo tin","ghiChu":"Cho nhóc tỳ biết tin các dòng dõi đỉnh cấp đã đến Bách Đoạn sơn (@c0114)."},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Hộ tống tiểu sư đệ","ghiChu":"Dẫn đội tới Bách Đoạn sơn"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Tiểu sư đệ ranh mãnh khiến Đào Dã nhiều phen nghẹn họng","ghiChu":"@c0117"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0113","@c0114","@c0115","@c0117"]},{"id":"bon-lao-tien-boi-bo-thien-cac","name":"Bốn lão tiền bối Bổ Thiên các","aliases":["Bốn lão già","Bốn vị lão tiền bối"],"gioiTinh":"nam","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0113","tieuDe":"Thử thân thể & giao nhiệm vụ","text":"Bốn cường giả Bổ Thiên các mắt ánh xanh tuyên bố đánh nhóc tỳ một trận để thử; kinh ngạc khen thân thể nó nghịch thiên khi nó phản kích gây tiếng sấm; can Hùng Phi, dỗ nhóc tỳ rồi giao nó vào Bách Đoạn sơn tìm Bất Lão thần tuyền, hứa khắc Bất Hủ Thần Bi và cho vào Tàng Kinh các chọn Bảo Thuật.","anchor":"quả nhiên đủ mạnh, thân thể như vậy cũng có thể xem như nghịch thiên rồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Thử thân thể nó rồi giao nhiệm vụ Bất Lão thần tuyền","ghiChu":"@c0113"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0113"]},{"id":"thieu-nu-ao-xanh-thien-tai-doanh","name":"Thiếu nữ áo xanh","gioiTinh":"nu","theLuc":[{"ten":"Thiên tài doanh","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0113","tieuDe":"Khiêu chiến đoạt linh dược","text":"Thiếu nữ ~15-16 tuổi, da trắng như tuyết, tóc như thác nước, mắt trong như thu thủy, bước tới nhận khiêu chiến nhóc tỳ để đoạt cây linh dược, mở màn ván tỉ thí.","anchor":"Ta tới khiêu chiến, thắng, có thể đưa cây linh dược của ngươi cho ta?"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bước tới khiêu chiến để đoạt cây linh dược của nó","ghiChu":"@c0113"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0113"]},{"id":"thieu-nu-ao-da-thu-thien-tai-doanh","name":"Thiếu nữ áo da thú","gioiTinh":"nu","theLuc":[{"ten":"Thiên tài doanh","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0113","tieuDe":"Nhận một phần ván cược","text":"Thiếu nữ da màu lúa mạch, cánh tay để trần, tính cách ngỗ ngược, bước lên nhận một phần cược trong ván đánh cược quanh cây linh dược, dọa cho nhóc tỳ không còn răng mà húp cháo.","anchor":"Ngươi quá tự tin, vậy thì tính ta một phần."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Nhận một phần ván cược, dọa đánh nhóc tỳ","ghiChu":"@c0113"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0113"]},{"id":"ngan-tam","name":"Ngạn Tâm","gioiTinh":"nu","trangThai":"song","blurb":"Thiếu nữ áo xanh da trắng ở Thiên tài doanh, dùng Phù Văn tạo gió cùng Khổng Tước xanh và lưới ngọc bích.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0114","tieuDe":"Đối thủ đầu tiên, thua nhanh","text":"Thiếu nữ áo xanh da trắng, dùng Phù Văn tạo gió dưới chân thả Khổng Tước xanh phát sáng tấn công rồi phản công bằng lưới ngọc bích; bị nhóc tỳ đánh tan Khổng Tước và lưới, bắt cổ tay xoay ra sau lưng đặt Phù Văn lên cổ khống chế, thua nhanh xấu hổ đỏ mặt.","anchor":"liền nắm lấy cổ tay của Ngạn Tâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ đấu cược","ghiChu":"Bị nhóc tỳ khống chế bắt sống (@c0114)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0114"]},{"id":"phieu-tuyet","name":"Phiêu Tuyết","gioiTinh":"nu","trangThai":"song","blurb":"Thiếu nữ áo da thú, da màu lúa mì, gợi cảm ngỗ ngược, dùng hào quang kết thành chiến mâu.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0114","tieuDe":"Đối thủ thứ hai, bị nghiền vũ khí","text":"Thiếu nữ áo da thú da màu lúa mì, dùng hào quang kết thành chiến mâu phá không đâm tới; bị nhóc tỳ né rồi tạo cối xay bạc nghiền tan chiến mâu, vọt tới nhấn eo phẩy chưởng làm rơi một cọng tóc — thua hoàn toàn.","anchor":"một cối xay màu bạc xuất hiện"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ đấu cược","ghiChu":"Bị nghiền tan chiến mâu, thua (@c0114)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0114"]},{"id":"so-ha","name":"Sở Hạ","aliases":["Thiếu niên áo tím"],"gioiTinh":"nam","theLuc":[{"ten":"Sở gia","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi sâu không lường) @c0115","trangThai":"song","vaiTro":"Con cháu Thượng Cổ thế gia Sở gia ở Hỏa quốc","tabs":{"diem":[{"text":"Thiếu niên áo tím ~17-18 tuổi, tu vi sâu không lường, chủ động kết minh","chuong":"@c0115"}],"kinhLich":[{"importance":"normal","chuong":"@c0115","tieuDe":"Chào kết minh với đoàn Bổ Thiên các","text":"Thiếu niên áo tím tự xưng Sở Hạ, đến từ Hỏa quốc, con cháu Thượng Cổ thế gia Sở gia, duỗi cành ô-liu kết minh với đoàn Bổ Thiên các; bị thiếu niên họ Cổ ra mỉa mai chuyện lôi kéo đồng minh.","anchor":"Ta là Sở Hạ, đến từ Hỏa quốc."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiếu niên họ Cổ","tag":"doi-thu","quanHe":"Bị mỉa mai chuyện kết minh","ghiChu":"Cổ gia tuyên bố không kết minh"}],"tuiDo":{}},"nguon":["@c0115"]},{"id":"thieu-nien-ho-co","name":"Thiếu niên họ Cổ","aliases":["Thiếu niên áo xanh Cổ gia"],"gioiTinh":"nam","theLuc":[{"ten":"Cổ gia","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Con cháu Cổ gia, ngạo mạn không kết minh","tabs":{"diem":[{"text":"Thiếu niên áo xanh, mỉa mai kẻ lôi kéo đồng minh","chuong":"@c0115"}],"kinhLich":[{"importance":"normal","chuong":"@c0115","tieuDe":"Từ chối kết minh, mỉa mai Sở Hạ","text":"Thiếu niên áo xanh của Cổ gia đi ra mỉa mai Sở Hạ lôi kéo đồng minh, tuyên bố Cổ gia không thèm kết minh.","anchor":"Ta là Sở Hạ, đến từ Hỏa quốc."}],"tuViMoc":[],"nhanMach":[{"ten":"Sở Hạ","tag":"doi-thu","quanHe":"Mỉa mai chuyện kết minh","ghiChu":""}],"tuiDo":{}},"nguon":["@c0115"]},{"id":"thieu-nien-nuoi-linh-tuoc","name":"Thiếu niên nuôi Linh Tước","aliases":[],"gioiTinh":"nam","trangThai":"song","vaiTro":"Chủ nhân con Linh Tước năm màu (Ma Cầm), thực lực khó lường","tabs":{"diem":[{"text":"Uống trà điềm nhiên, thả Linh Tước diệt sạch đám tranh đấu","chuong":"@c0115"}],"kinhLich":[{"importance":"normal","chuong":"@c0115","tieuDe":"Thả Linh Tước nuốt sống mấy chục người","text":"Khi con cháu hai gia tộc động thủ trên phố, thiếu niên đang uống trà ở quán vỗ bàn quát; con Linh Tước năm màu trên vai bay lên hút thành vòng xoáy, nuốt mấy chục người và nghiền nát trong miệng rồi bay về, khiến cả phố lặng ngắt.","anchor":"mấy chục người vỡ nát trong miệng nó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"linhThu":[{"ten":"Linh Tước năm màu","moTa":"Ma Cầm năm màu trên vai, thần thông nuốt người thành vòng xoáy.","nguon":"@c0115"}]}},"nguon":["@c0115"]},{"id":"phu-xe-tay-lang-thu-son","name":"Phu xe Tây Lăng thú sơn","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tây Lăng thú sơn","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Cường giả Nhân tộc đánh xe cho tiểu Bạch Hổ","tabs":{"diem":[{"text":"Cứng rắn đối chọi Bổ Thiên các, truyền lời của Bạch Hổ","chuong":"@c0115"}],"kinhLich":[{"importance":"normal","chuong":"@c0115","tieuDe":"Đối chọi Bổ Thiên các, hẹn quyết chiến Bách Đoạn sơn","text":"Phu xe Nhân tộc kéo xe cho tiểu Bạch Hổ; khi nữ đệ tử Bổ Thiên các lỡ lời, hắn bắt tự vả miệng, Bạch Hổ muốn ăn thịt nàng. Trước hồ lô Phù Văn của Đào Dã, phu xe đổi sắc mặt nhưng đáp trả rằng họ đến từ Tây Lăng thú sơn, hẹn gặp lại ở Bách Đoạn sơn.","anchor":"chúng ta tới từ Tây Lăng thú sơn"}],"tuViMoc":[],"nhanMach":[{"ten":"Đào Dã","tag":"doi-thu","quanHe":"Đối chọi trên phố Đoạn Không thành","ghiChu":""}],"tuiDo":{}},"nguon":["@c0115"]},{"id":"sư-tu-chin-dau","name":"Sư Tử chín đầu","aliases":["Hoàng Kim sư tử","Cửu đầu sư tử","Hoàng Kim sư tử chín đầu"],"gioiTinh":"nam","canhGioiCaoNhat":"Sinh linh cận thuần huyết Thái Cổ (@c0116)","trangThai":"song","blurb":"Sinh linh Hoàng Kim sư tử chín đầu cận thuần huyết, hống lên tuyên bố chọn kẻ nhân loại (Hạo Thiên) làm nô bộc.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0116","tieuDe":"Tuyên bố chọn kẻ nhân loại làm nô bộc","text":"Tại tế đàn cổ trong Đoạn Không thành, con sư tử chín đầu cận thuần huyết hống lên tuyên bố đã chọn kẻ nhân loại (Hạo Thiên) làm nô bộc, cấm kẻ khác tranh; sư tỷ nhắc nó cách thuần huyết không xa, hiếm thiên tài Nhân tộc đối kháng nổi ngoài Thạch Nghị và vài người.","anchor":"kẻ nhân loại này ta đã chọn rồi"},{"importance":"normal","chuong":"@c0118","tieuDe":"Được nhắc là kẻ muốn thu phục nhóc tỳ","text":"Sinh vật hình người ánh bạc nhắc Hoàng Kim sư tử chín đầu là cường giả muốn thu phục nhóc tỳ, làm dấy lên cuộc tranh đoạt nhóc tỳ giữa các thế lực.","anchor":"Hoàng Kim sư tử chín đầu nói muốn thu phục ngươi, ta lại không muốn cho hắn được toại nguyện"},{"importance":"normal","chuong":"@c0122","tieuDe":"Đại chiến rồi thất bại trước Nhóc tỳ","text":"Đại chiến Nhóc tỳ trên thảo nguyên, tung Sư Hống công, chín răng nanh phi kiếm do trưởng bối tặng, chuỗi niệm châu vàng và cả thần thông trấn tộc Vô Úy Sư Tử ấn; bị Cốt Tiễn của Nhóc tỳ làm một đầu lâu suýt nứt, huyết thấm đỏ mắt; tiêu hao quá nhiều tinh khí thần nên bỏ chạy, cuối cùng bị Nhóc tỳ nhảy lên lưng dùng sấm sét trấn áp.","anchor":"một cái đầu lâu suýt chút nữa nứt ra, xuất hiện một vết thương cực kỳ kinh khủng"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn bắt làm nô bộc","ghiChu":"Chọn kẻ nhân loại Hạo Thiên làm nô bộc, cấm kẻ khác tranh"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn thu phục nhóc tỳ","ghiChu":"@c0118"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ đánh bại mình và cưỡi khống chế làm thú cưỡi","ghiChu":"Gặp @c0122"}],"tuiDo":{}},"nguon":["@c0116","@c0118","@c0122"]},{"id":"phong-nhi","name":"Phong nhi","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Vũ tộc","trangThai":"gan-bo"},{"ten":"Bổ Thiên các","trangThai":"gia-mao"}],"trangThai":"song","blurb":"Người của Vũ tộc cài cắm trong Bổ Thiên các, truyền tin xác định danh tính Hạo Thiên về cho Vũ tộc.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0116","tieuDe":"Truyền tin xác định danh tính Hạo Thiên","text":"Người của Vũ tộc cài cắm ở Bổ Thiên các, truyền tin về xác định tên nhóc ở Hư Thần giới là Hạo Thiên, hiện đang ở Đoạn Không thành, giúp Vũ tộc quyết định mưu diệt.","anchor":"nó tên là Hạo Thiên, hiện nay đã đến Đoạn Không thành"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Chỉ điểm danh tính","ghiChu":"Truyền tin xác định Hạo Thiên cho Vũ tộc"}],"tuiDo":{}},"nguon":["@c0116"]},{"id":"sinh-vat-hinh-nguoi-anh-bac","name":"Sinh vật hình người ánh bạc","aliases":["Sinh linh màu bạc","Sinh linh hình người màu bạc"],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ (@c0118)","trangThai":"song","blurb":"Cường giả bí ẩn toàn xương dáng người, con ngươi màu bạc, từ sâu dãy núi đi ra; muốn thu phục nhóc tỳ làm chiến bộc.","vaiTro":"Đối thủ mới trong tiểu thế giới","tabs":{"diem":[{"text":"Khắp thân ánh bạc, con ngươi màu bạc, khí tức lạnh giá, khi nói phát làn sóng chấn động như biển cả và sóng triều","chuong":"@c0118"}],"kinhLich":[{"importance":"normal","chuong":"@c0118","tieuDe":"Phục kích nhóm Bổ Thiên các đoạt Xích Lan","text":"Từ sâu núi đi ra, soi bức tranh xác nhận mục tiêu, giẫm sập vách đá trút cự thạch vạn cân suýt chôn vùi sư huynh và nhóc tỳ, ngắt cả bốn gốc Xích Lan; tự xưng là vương/chủ nhân của nhóc tỳ, đòi nhóc tỳ đi theo lập chiến công, nhắc Hoàng Kim sư tử chín đầu muốn thu phục nhóc tỳ.","anchor":"Ta là vương của ngươi, sau này ngươi đi theo bên người ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn thu nhóc tỳ làm chiến bộc; bị nhóc tỳ coi như món ăn","ghiChu":"@c0118"},{"ten":"Sư Tử chín đầu","tag":"doi-thu","quanHe":"Nhắc Hoàng Kim sư tử chín đầu là kẻ tranh đoạt nhóc tỳ","ghiChu":"@c0118"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0118"]},{"id":"dai-hong","name":"Đại Hồng","aliases":["Hỏa Vân Tước"],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ (@c0118)","trangThai":"song","blurb":"Hung cầm đỏ rực tính hung tợn, nghi là đời sau Thái Cổ di chủng; thịt là huyết nhục bảo dược.","vaiTro":"Hung cầm bị nhóc tỳ săn đuổi","tabs":{"diem":[{"text":"Chim đỏ rực nổi điên trút mưa Hỏa văn biến rừng thành biển lửa; nghi là đời sau Thái Cổ di chủng","chuong":"@c0118"}],"kinhLich":[{"importance":"normal","chuong":"@c0118","tieuDe":"Bị nhóc tỳ đả thương giả chết trốn thoát","text":"Trút mưa Hỏa văn biến rừng thành biển lửa, bị nhóc tỳ dùng tia chớp vàng, trăng bạc và Ma Cầm đả thương, rớt hơn hai mươi cân thịt; gia trì Bảo Thuật tăng tốc, giả chết bay sát đất trốn thoát; thịt của nó là huyết nhục bảo dược.","anchor":"Một khối thịt rớt ra, con chim rơi xuống cực nhanh."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị nhóc tỳ đả thương và đoạt thịt","ghiChu":"@c0118"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0118"]},{"id":"nhan-hung-mot-sung-mau-den","name":"Nhân Hùng một sừng màu đen","aliases":[],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ (@c0118)","trangThai":"song","blurb":"Hung thú một sừng màu đen biết nói tiếng người, sợ nhóc tỳ hung tàn nên bỏ chạy.","vaiTro":"Hung thú thoáng qua","tabs":{"diem":[{"text":"Hung thú một sừng màu đen biết nói tiếng người, sợ hãi bỏ chạy vì nhóc tỳ vừa gặp đã định ăn thịt","chuong":"@c0118"}],"kinhLich":[{"importance":"normal","chuong":"@c0118","tieuDe":"Bỏ chạy khỏi nhóc tỳ hung tàn","text":"Nhân Hùng một sừng màu đen sợ hãi bỏ chạy vì thằng bé hung tàn vừa gặp đã định ăn thịt nó, thốt lên tiếng người rằng thật hung tàn; nhóc tỳ tiếc tay gấu bị chạy mất.","anchor":"Thật hung tàn!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị nhóc tỳ định ăn thịt nên bỏ chạy","ghiChu":"@c0118"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0118"]},{"id":"sinh-linh-mau-bac","name":"Sinh linh màu bạc","aliases":["Vương tương lai"],"gioiTinh":"nam","theLuc":[{"ten":"Vương tộc (Thái Cổ di chủng)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cảnh giới cao hơn Thạch Hạo nhưng thua ở Bảo Cụ (@c0119)","trangThai":"tu-vong","blurb":"Thái Cổ di chủng hậu duệ Vương tộc, thân người phủ vảy bạc mắt bạc tóc bạc, tự xưng là một vị Vương trong tương lai; bị Thạch Hạo giết trong trận đơn đấu.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0119","tieuDe":"Lộ chân thân, tử chiến Thạch Hạo","text":"Bị nhóc tỳ đòi ăn thịt nên tức giận thu ngân quang lộ chân thân thân người phủ vảy bạc, tự xưng “Vương tương lai”; dùng Phù Văn, bảo phiến bạc, chủy thủ bạc giao chiến; nhận ra đối thủ chiếm Bảo cốt Toan Nghê luyện chí bảo; bị Cốt Tiễn vàng bẻ gãy chủy thủ, chặt tay trái, cưỡi bảo phiến bỏ chạy rồi bị cắt cổ, đầu lâu đánh thành tro.","anchor":"ngân quang thu lại, lộ ra chân thân"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị Thạch Hạo giết trong trận đơn đấu","ghiChu":""},{"ten":"Sư Tử chín đầu","tag":"khac","quanHe":"Nhắc Sư Tử chín đầu muốn thu Thạch Hạo làm chiến phó","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Cây quạt màu bạc","loai":"Bảo Cụ","trangThai":"bi-cuop","moTa":"Bảo phiến bạc phun ra tạo sóng bạc san bằng dãy núi; sau bị Thạch Hạo cướp và hủy hơn nửa.","nguon":"@c0119"},{"ten":"Chủy thủ màu bạc","loai":"Bảo Cụ","trangThai":"hong","moTa":"Dao găm xương bạc mài từ Bảo Cốt, phun ra như đòn thứ ba; bị Cốt Tiễn vàng xoắn đứt làm hai đoạn.","nguon":"@c0119"}]}},"nguon":["@c0119"]},{"id":"hoa-linh-nhi","name":"Hỏa Linh Nhi","aliases":["Công chúa Hỏa quốc","con gái Nhân Hoàng","Con gái nhỏ của Nhân Hoàng","Con gái Nhân Hoàng","Tiểu công chúa","Sư muội","Tiểu công chúa Hỏa quốc"],"gioiTinh":"nu","theLuc":[{"ten":"Bổ Thiên các","trangThai":"gan-bo"},{"ten":"Nhân Hoàng","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Con gái nhỏ của Nhân Hoàng, sư muội cùng môn Bổ Thiên các, được Nhân Hoàng thương yêu nhất; đi trên xe phượng đỏ thẫm có hơn bốn mươi thiên tài hộ tống.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0119","tieuDe":"Xuất hiện trên xe phượng, đồng ý trao đổi","text":"Ngồi xe kéo mây đỏ lấp loé hào quang đỏ thẫm với hơn bốn mươi thiên tài hộ tống; được các thiên tài Bổ Thiên các nhận ra là con gái nhỏ của Nhân Hoàng và sư muội cùng môn; đồng ý trao đổi Thái Cổ di chủng với Thạch Hạo.","anchor":"chúng ta đồng ý trao đổi"},{"importance":"normal","chuong":"@c0120","tieuDe":"Lộ diện và chiêu mộ nhóc tỳ","text":"Từ trong xe kéo quyết đổi Tử Vân Tâm lấy con Linh Tộc dù nhiều người can; vén rèm châu ngọc bước ra, lộ tên khi cười nhạo nhóc tỳ chiếm hô sư muội; nhận ra đây là nhóc siêu quậy nên ra lệnh vây bắt; về sau kìm nén kích động chủ động chiêu mộ nhóc tỳ, tiết lộ đã liên hệ Hoàng Kim sư tử chín đầu, Vũ Vương, Ngân Huyết Cự Nhân để đi Thần Quật đoạt chí bảo; cuối cùng bị nhóc tỳ vỗ mông.","anchor":"Khóe miệng Hỏa Linh Nhi hơi vểnh lên, mang theo một tia cười nhạo"},{"importance":"normal","chuong":"@c0121","tieuDe":"Truy sát nhóc tỳ, giục thu phục sư tử","text":"Tức giận phun lửa hóa chim tước đỏ đánh nhóc tỳ, bị Nguyệt bàn chắn; ra điều kiện tới Thần Quật không được xung đột với Hoàng Kim sư tử chín đầu; bị nhóc tỳ chọc “giảm béo” liền dệt Phù Văn thành đôi cánh Chu Tước truy sát biến thảo nguyên thành biển lửa; sau đó giục Sư Tử chín đầu mau thu phục nhóc tỳ.","anchor":"Phù Văn đan dệt, ở phía sau lưng biến thành một đôi cánh Chu Tước"},{"chuong":"@c0123","importance":"normal","tieuDe":"Dẫn đoàn vào Thần Quật, đoạt trứng vàng","text":"Kêu gọi liên thủ tiến vào Thần Quật, mắng nhóc tỳ “quỷ nhát gan” rồi dẫn hơn mười thiên tài Nhân tộc cùng Ngân Huyết, Vũ Vương vào; thu được quả trứng vàng nghi là hậu duệ Lang Thần, bị thương lao ra và tranh giành khi trứng rơi, cuối cùng bị nhóc tỳ cướp trứng.","anchor":"Cuối cùng, Hỏa Linh Nhi dẫn theo hơn mười gã thiên tài Nhân tộc tiến vào Thần Quật."},{"importance":"normal","chuong":"@c0124","tieuDe":"Truy đuổi cả đêm, đại chiến giành trứng","text":"Cùng Ngân Huyết Cự Nhân và Vũ Vương chạy vòng cả đêm quanh thảo nguyên rồi quay về điểm xuất phát, tức đến hộc máu; nhờ U Lan Thảo tìm được nhóc tỳ đang nướng trứng liền giận run người xông vào đại chiến, dùng hỏa thuật nhưng bị nhóc tỳ lợi dụng để nấu trứng.","anchor":"Tất cả mọi người đều đồng thời xông về phía trước"},{"importance":"normal","chuong":"@c0125","tieuDe":"Nuôi Ấu Thần cùng Thạch Hạo","text":"Ngăn Thạch Hạo hành hạ sói con, bị hỏi có sữa không nên nổi trận lôi đình đuổi đánh hai giờ; đem hai cây Linh dược và trái tim hung thú trong đỉnh ngọc nuôi Ấu Thần; nhận giữ nuôi Ấu Thần khi Thạch Hạo cưỡi Sư Tử rời đi, tức điên vì sói con tham ăn giống Thạch Hạo.","anchor":"Cuối cùng trận truy sát này kéo dài tận hai giờ thì mọi người mới ngồi lại."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Sư huynh cùng môn, thỏa thuận trao đổi Thái Cổ di chủng","ghiChu":""},{"ten":"Nhân Hoàng","tag":"cha-me","quanHe":"Cha, thương yêu nàng nhất","ghiChu":""},{"ten":"Thạch Hạo","tag":"dong-minh","quanHe":"Bị nhóc tỳ gọi đùa là sư muội rồi ra lệnh vây bắt; sau lại chiêu mộ nhóc tỳ vào liên minh đi Thần Quật, bị nhóc tỳ vỗ mông trêu ngược.","ghiChu":"@c0120"},{"ten":"Nhân Hoàng","tag":"cha-me","quanHe":"Cha của Hỏa Linh Nhi, mời chào một nửa số thiên tài đi bảo vệ con gái.","ghiChu":"@c0120"},{"ten":"Thạch Hạo","tag":"su-mon","quanHe":"Đồng môn Bổ Thiên các (sư huynh), bị nàng truy sát vì bị chọc","ghiChu":"@c0121"},{"ten":"Hoàng Kim sư tử chín đầu","tag":"khac","quanHe":"Giục nó mau thu phục nhóc tỳ","ghiChu":"@c0121"},{"ten":"Người khổng lồ Ngân Huyết","tag":"dong-hanh","quanHe":"Cùng dẫn vào Thần Quật","ghiChu":"@c0123"},{"ten":"Vũ Vương","tag":"dong-hanh","quanHe":"Cùng vào Thần Quật","ghiChu":"@c0123"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ giành trứng thần","ghiChu":"Bị nhóc tỳ trêu tức, hỏa thuật của nàng bị lợi dụng nấu trứng (@c0124)"},{"ten":"Ấu Thần","tag":"khac","quanHe":"Nuôi dưỡng Ấu Thần như cha mẹ nuôi","ghiChu":"Cho ăn Linh dược và trái tim hung thú"}]},"nguon":["@c0119","@c0120","@c0121","@c0123","@c0124","@c0125"]},{"id":"nguoi-mac-ao-khoac-mau-den","name":"Người mặc áo khoác màu đen","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hỏa quốc","trangThai":"danh-nghia"}],"trangThai":"song","blurb":"Kẻ thần bí giọng khàn, khói đen lượn lờ quanh thân, phục vụ bên xe kéo công chúa Hỏa quốc.","vaiTro":"Người xác nhận Linh Tộc và trao Tử Vân Tâm trong thương lượng trao đổi.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0120","tieuDe":"Xác nhận Linh Tộc và trao Tử Vân Tâm","text":"Từ chỗ xe kéo ra xác nhận con sinh linh màu bạc là Linh Tộc, Thái Cổ di chủng có Vương huyết truyền thừa; cầm đỉnh ngọc hình vuông chứa Tử Vân Tâm đến trao đổi với nhóc tỳ.","anchor":"Đây chính là Tử Vân Tâm, là trái tim của một con Thái Cổ di chủng hung mãnh"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"khac","quanHe":"Xác nhận Linh Tộc và trao đỉnh ngọc chứa Tử Vân Tâm để đổi lấy con sinh linh màu bạc của nhóc tỳ.","ghiChu":"@c0120"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0120"]},{"id":"sinh-linh-hinh-nguoi-moc-sung","name":"Sinh linh hình người mọc sừng","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Vũ tộc (Hoàng Đô Thạch quốc)","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Dị tộc người của Vũ Vương, đầu mọc một sừng, lưng mọc đôi lông cánh.","vaiTro":"Dị tộc rủ nhóc tỳ làm tôi tớ, bị đánh chết hóa than.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0120","tieuDe":"Rủ nhóc tỳ làm tôi tớ rồi bị giết","text":"Đối chiếu tranh nhận ra nhóc tỳ là kẻ mà Hoàng Kim sư tử chín đầu tranh nhau muốn thu làm chiến sủng, rồi rủ nó đầu nhập Vương của hắn làm tôi tớ; bị nhóc tỳ nổi giận đánh một chưởng Phù Văn hóa thành than.","anchor":"mấy tên Dị tộc này đều bị xuyên thủng, hóa thành tro tàn"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Rủ nhóc tỳ làm tôi tớ cho Vương của hắn, bị nhóc tỳ đánh chết hóa than.","ghiChu":"@c0120"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0120"]},{"id":"hoa-kim-su-tu-chin-dau-nv","name":"Hoàng Kim sư tử chín đầu","gioiTinh":"khac","aliases":["Sư Tử chín đầu","Hoàng Kim sư tử"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Thái Cổ di chủng","trangThai":"gan-bo"}],"vaiTro":"Thái Cổ di chủng cầm đầu chặn ải Thần Quật","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0121","tieuDe":"Tranh thu nhóc tỳ, đại chiến ngang sức","text":"Toàn thân vảy vàng ròng, Phù Văn cao siêu, huyết mạch kinh người; mở bức tranh nhận ra nhóc tỳ là chiến phó mạnh mẽ nó tìm, đánh văng hai kẻ kia để độc chiếm; chặn ải bằng móng vuốt ngàn tấn, chín đầu mỗi đầu phun một phi kiếm hoàng kim; đại chiến với nhóc tỳ, bị Nghịch chuyển phản đòn nhưng dùng di hình hoán vị né, cuối cùng ngang sức nhóc tỳ.","anchor":"chín thanh phi kiếm đều có màu hoàng kim"},{"chuong":"@c0123","importance":"normal","tieuDe":"Bại trận, bỏ trốn vào Thần Quật","text":"Bộc phát hào quang vàng chống trả nhóc tỳ, phóng chín hạt niệm châu và chín răng nanh hóa phi kiếm; bị nhóc tỳ dùng Cốt Tiễn hóa giao long chém rụng bốn đầu lâu, thu bảo cụ bỏ trốn sát mặt đất rồi nhảy vào lỗ đen Thần Quật; sau lao ra cuối cùng đầy máu, tuyên bố đây là Ma thổ nuôi sói của Lang Thần.","anchor":"Nó không có nghịch thiên như nhóc tỳ, không thể lấy bảo thuật cứng rắn mà chống đỡ Long Giao tiễn được."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn thu làm chiến phó rồi giao chiến ngang sức","ghiChu":"@c0121"},{"ten":"Ngân Huyết cự nhân","tag":"doi-thu","quanHe":"Cùng tranh thu nhóc tỳ, bị nó đánh văng","ghiChu":"@c0121"},{"ten":"Vũ Vương","tag":"doi-thu","quanHe":"Cùng tranh thu nhóc tỳ, bị nó đánh văng","ghiChu":"@c0121"},{"ten":"Hỏa Linh Nhi","tag":"doi-thu","quanHe":"Cùng đám sinh linh tranh đoạt trứng vàng, cùng vào Thần Quật","ghiChu":"@c0123"}],"tuiDo":{}},"nguon":["@c0121","@c0123"]},{"id":"ngan-huyet-cu-nhan","name":"Ngân Huyết cự nhân","gioiTinh":"khac","aliases":["Người khổng lồ Ngân Huyết","Người khổng lồ màu bạc"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Thái Cổ di chủng","trangThai":"gan-bo"}],"vaiTro":"Sinh linh khổng lồ màu bạc trong nhóm Thái Cổ di chủng chặn Thần Quật","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0121","tieuDe":"Tranh thu nhóc tỳ, bị đấm chảy máu tay","text":"Sinh linh khổng lồ màu bạc cao mười mấy mét, tự xưng quá khứ vô địch, muốn thu nhóc tỳ làm người hầu; bị nhóc tỳ đấm khiến bàn tay như cái gầu to không ngừng chảy máu.","anchor":"bàn tay như cái gầu to không ngừng chảy máu"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn thu làm người hầu, bị nhóc tỳ đấm chảy máu tay","ghiChu":"@c0121"}],"tuiDo":{}},"nguon":["@c0121"]},{"id":"vu-vuong-di-chung","name":"Vũ Vương","gioiTinh":"khac","aliases":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Thái Cổ di chủng","trangThai":"gan-bo"},{"ten":"Vũ tộc","trangThai":"gan-bo"}],"vaiTro":"Sinh linh Vũ tộc hình người sừng vàng cánh ngũ sắc trong nhóm chặn Thần Quật","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0121","tieuDe":"Tranh thu nhóc tỳ, bị đá văng hộc máu","text":"Sinh linh Vũ tộc hình người, sừng vàng, cánh ngũ sắc; muốn thu nhóc tỳ vì Nhân tộc và Vũ tộc hình dáng gần giống; bị đùi phải nhóc tỳ phát tia chớp vàng đá văng, khóe miệng tràn máu.","anchor":"Toàn bộ đùi phải của nhóc tỳ đều phát sáng, tia chớp màu vàng óng"},{"chuong":"@c0123","importance":"normal","tieuDe":"Vào Thần Quật, thoát ra thương vong","text":"Cùng Ngân Huyết theo đoàn Hỏa Linh Nhi vào Thần Quật; đôi cánh năm màu nát bét vọt ra, thủ hạ chết gần hết, giật mình khi biết trứng vàng có thể là hậu duệ Lang Thần.","anchor":"Không phải Thần Quật, đây là Ma Quật mà!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Muốn thu làm chiến sủng, bị nhóc tỳ đá văng hộc máu","ghiChu":"@c0121"},{"ten":"Hỏa Linh Nhi","tag":"dong-hanh","quanHe":"Cùng vào Thần Quật","ghiChu":"@c0123"}],"tuiDo":{}},"nguon":["@c0121","@c0123"]},{"id":"moc-phong-linh-toc","name":"Mộc Phong","gioiTinh":"nam","aliases":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","theLuc":[{"ten":"Hư Thần Giới","trangThai":"gan-bo"}],"vaiTro":"Nhân vật Linh tộc đi tìm nhóc tỳ và bị ăn thịt","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0121","tieuDe":"Đi tìm nhóc tỳ, bị ăn thịt","text":"Mấy ngày trước đi tìm nhóc tỳ nhưng một đi không trở lại; Hoàng Kim sư tử đoán đã chết, nhóc tỳ xác nhận đã ăn thịt Mộc Phong khiến cả đám Dị tộc kinh sợ.","anchor":"Bị ta ăn thịt rồi."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đi tìm nhóc tỳ rồi bị nhóc tỳ ăn thịt","ghiChu":"@c0121"}],"tuiDo":{}},"nguon":["@c0121"]},{"id":"nguoi-khong-lo-ngan-huyet","name":"Người khổng lồ Ngân Huyết","cn":"","aliases":["Ngân Huyết cự nhân"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Sinh linh Dị tộc người khổng lồ Ngân Huyết, theo đoàn Hỏa Linh Nhi vào Thần Quật rồi lao ra đầy máu tuyên bố đây là Ma Quật.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Do dự cân nhắc trước hiểm nguy, tranh đoạt bảo vật quyết liệt","chuong":"@c0123"}],"tabs":{"diem":[{"text":"Sinh linh Dị tộc thân hình khổng lồ, thuộc nhóm cường giả tiến vào Thần Quật","chuong":"@c0123"}],"kinhLich":[{"chuong":"@c0123","importance":"normal","tieuDe":"Vào Ma Quật rồi tranh trứng vàng","text":"Do dự rồi theo đoàn Hỏa Linh Nhi vào Thần Quật; sáng sớm lao ra đầy máu tuyên bố đây không phải Thần Quật mà là Ma Quật, thủ hạ chết gần hết; cùng tranh cướp quả trứng vàng khi trứng rơi ra.","anchor":"Không phải Thần Quật, đây là Ma Quật mà!"}],"tuViMoc":[],"nhanMach":[{"ten":"Hỏa Linh Nhi","tag":"dong-hanh","quanHe":"Cùng vào Thần Quật, sau tranh trứng vàng","ghiChu":"@c0123"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0123"]}]};
